INSERT INTO quotes (id, movie_id, text, character) VALUES
  (8101, 213, 'If you accept the belief that a high Trendex means a rising sales curve...', NULL),
  (8102, 213, 'You better walk me to the Plaza.', NULL),
  (8103, 213, 'I made him feel like a good Samaritan.', NULL),
  (8104, 213, 'Remind her we have theatre tickets for tonight.', NULL),
  (8105, 213, 'I was saying that you may be slow in starting, but there''s nobody faster.', NULL),
  (8106, 213, 'Could you send it for me if I write it out for you?', NULL),
  (8107, 213, 'I left some friends back there in the Oak Bar.', NULL),
  (8108, 213, 'I''m so glad you''re pleased, Mr.', NULL),
  (8109, 213, 'I get unreasonable about things like that.', NULL),
  (8110, 213, 'I know you''re a man of many names, but I''ll accept your current choice.', NULL),
  (8111, 213, 'Now, shall we get down to business?', NULL),
  (8112, 213, 'Why don''t you surprise me, Mr.', NULL),
  (8113, 213, 'I''ve never been in Pittsburgh.', NULL),
  (8114, 213, 'In two days, you are due at the Ambassador East in Chicago.', NULL),
  (8115, 213, 'For the simple reason that I simply don''t know what you''re talking about.', NULL),
  (8116, 213, 'I want this man examined for driving while intoxicated.', NULL),
  (8117, 213, 'What am I, a telephone operator?', NULL),
  (8118, 213, 'Get my lawyer right away and come and bail me out.', NULL),
  (8119, 213, 'You may refuse to permit a blood test to be made...', NULL),
  (8120, 213, 'I''m certain it must''ve happened.', NULL),
  (8121, 213, 'If I were brought in dead, you still wouldn''t believe...', NULL),
  (8122, 213, 'I remember when it used to come in bottles.', NULL),
  (8123, 213, 'Roger, you said you were going to call a cab.', NULL),
  (8124, 213, 'Finally, he told us he had to go home to sleep it off.', NULL),
  (8125, 213, 'He''s addressing the General Assembly this afternoon.', NULL),
  (8126, 213, 'I don''t see why you want me along.', NULL),
  (8127, 213, 'Mother, do me a favor, will you?', NULL),
  (8128, 213, 'I wonder if I look like Kaplan.', NULL),
  (8129, 213, 'Can I help it if you''re never around, Mr.', NULL),
  (8130, 213, 'You called down on the phone and described the suit to me.', NULL),
  (8131, 213, 'Obviously they''ve mistaken me for a much shorter man.', NULL),
  (8132, 213, 'We''re back to that one, are we?', NULL),
  (8133, 213, 'Did you have an appointment, sir?', NULL),
  (8134, 213, 'I''ve been staying in my apartment in town for the last month.', NULL),
  (8135, 213, 'Kaplan, tell me who you are and what you want.', NULL),
  (8136, 213, 'Why is it I feel like laughing?', NULL),
  (8137, 213, 'Vandamm and company or the police?', NULL),
  (8138, 213, 'If we make the slightest move to suggest there''s no such agent as George Kaplan...', NULL),
  (8139, 213, 'Because there''s no place to hide on a plane if anyone should recognize me.', NULL),
  (8140, 213, 'Something wrong with your eyes?', NULL),
  (8141, 213, 'Somehow they seem to put me at a disadvantage.', NULL),
  (8142, 213, 'What makes you think you have to conceal it?', NULL),
  (8143, 213, 'What do you do besides lure men to their doom on the 20th Century Limited?', NULL),
  (8144, 213, 'I have a large drawing room all to myself.', NULL),
  (8145, 213, 'You better go out and tell those police to hurry.', NULL),
  (8146, 213, 'We might have happened to leave at the same time but not together.', NULL),
  (8147, 213, 'Perhaps he got off when you got on?', NULL),
  (8148, 213, 'Either hurry up or get me a snorkel.', NULL),
  (8149, 213, 'Don''t you think it''d be a better idea if you stayed in my hotel room...', NULL),
  (8150, 213, 'You''ve got taste in clothes, taste in food...', NULL),
  (8151, 213, 'Don''t bother with the washroom.', NULL),
  (8152, 213, 'I mean, have you seen the man we''re looking for?', NULL),
  (8153, 213, 'Kaplan won''t mind a few wrinkles.', NULL),
  (8154, 213, 'Where do you propose I do that?', NULL),
  (8155, 213, 'It''s about an hour-and-a-half''s drive from Chicago.', NULL),
  (8156, 213, 'You better go before the police run out of redcaps.', NULL),
  (8157, 213, 'That plane''s dusting crops where there ain''t no crops.', NULL),
  (8158, 213, 'After all those explicit directions he gave you on the phone.', NULL),
  (8159, 213, 'What are you going to do next?', NULL),
  (8160, 213, 'Wouldn''t it be nice if my problems and your plans were somehow connected?', NULL),
  (8161, 213, 'I want you to do a favor for me.', NULL),
  (8162, 213, 'There won''t be anything more between us.', NULL),
  (8163, 213, 'Couldn''t he have taken an hour?', NULL),
  (8164, 213, 'Think I''ll take that cold shower after all.', NULL),
  (8165, 213, 'What possessed you to come blundering in here like this?', NULL),
  (8166, 213, 'I thought you just collected corpses.', NULL),
  (8167, 213, 'Then, you play the fugitive...', NULL),
  (8168, 213, 'Am I to be dropped into a vat of molten steel...', NULL),
  (8169, 213, 'Me in the hands of the police.', NULL),
  (8170, 213, 'How do we know it''s not a fake?', NULL),
  (8171, 213, 'I haven''t finished bidding yet.', NULL),
  (8172, 213, 'We''ve got a man here who answers to the description of Thornhill, Roger.', NULL),
  (8173, 213, 'Does anyone mind if I sit down?', NULL),
  (8174, 213, 'Then why did you let the police chase me all over the map?', NULL),
  (8175, 213, 'You could say he''s a sort of importer-exporter.', NULL),
  (8176, 213, 'He''s got short sleeves and dandruff!', NULL),
  (8177, 213, 'You should give me a medal and a vacation instead of asking me to be a target...', NULL),
  (8178, 213, 'If there was a chance of changing your mind I''d talk about Miss Kendall...', NULL),
  (8179, 213, 'I don''t know that I care to accept that charge.', NULL),
  (8180, 213, 'I suppose you were surprised to get my call.', NULL),
  (8181, 213, 'Suppose I tell you that I not only know when you''re leaving the country tonight...', NULL),
  (8182, 213, 'I want her to get what''s coming to her.', NULL),
  (8183, 213, 'I''m offering you a chance to save it.', NULL),
  (8184, 213, 'I didn''t want you to go on thinking...', NULL),
  (8185, 213, 'Yes, I thought I was quite graceful.', NULL),
  (8186, 213, 'Eventually, the Professor and his Washington colleagues approached me...', NULL),
  (8187, 213, 'Couldn''t we stand like this for just a few hours?', NULL),
  (8188, 213, 'After your malevolent friend Vandamm takes off tonight...', NULL),
  (8189, 213, 'You said that after tonight...', NULL),
  (8190, 213, 'That''s where I hit the chair doing that phony fall in the cafeteria.', NULL),
  (8191, 213, 'Inside of an hour, she''ll be gone.', NULL),
  (8192, 213, 'There''s nothing to worry about.', NULL),
  (8193, 213, 'I wonder if I might have a few words of parting with you, sir?', NULL),
  (8194, 213, 'Why else would you''ve decided not to tell her that...', NULL),
  (8195, 213, 'She removed any doubts you may have had about her...', NULL),
  (8196, 213, 'You''re not taking her on that plane with you?', NULL),
  (8197, 213, 'One of my most valuable attributes...', NULL),
  (8198, 213, 'I think I left my earrings upstairs.', NULL),
  (8199, 213, 'Whatever you do, don''t get on that plane!', NULL),
  (8200, 213, 'Tell your knife-throwing chum that I''ve reassured his wife.', NULL),
  (8401, 221, 'Mixed up in that beating on 12th Street?', NULL),
  (8402, 221, 'He doesn''t like one thing about me.', NULL),
  (8403, 221, 'And we were going to celebrate Easter.', NULL),
  (8404, 221, 'Is that why you were wandering around at 1:00 a.', NULL),
  (8405, 221, 'If you''re not as close to him as you''d like to be...', NULL),
  (8406, 221, 'We''ll ask your dad to come and pick you up.', NULL),
  (8407, 221, 'Your mother will be down to pick you up.', NULL),
  (8408, 221, 'Where were you tonight, Jimbo?', NULL),
  (8409, 221, 'Is that what they call you, or do you have a nickname?', NULL),
  (8410, 221, 'Where''s your mother tonight, Plato?', NULL),
  (8411, 221, 'We haven''t seen him now in a long time.', NULL),
  (8412, 221, 'Crawford don''t believe in them, sir.', NULL),
  (8413, 221, 'Can''t you wait till we get home?', NULL),
  (8414, 221, 'You see, we just moved here...', NULL),
  (8415, 221, 'We give you love and affection, don''t we?', NULL),
  (8416, 221, 'A minute ago, you said you didn''t care if he drinks.', NULL),
  (8417, 221, 'How come you''re not wearing your boots?', NULL),
  (8418, 221, 'That''s what you want, isn''t it?', NULL),
  (8419, 221, 'You had a good start in the wrong direction.', NULL),
  (8420, 221, 'Things pretty rough for you at home?', NULL),
  (8421, 221, 'I mean, I love him and all that type of stuff.', NULL),
  (8422, 221, 'I''ll tell you one thing, I don''t ever want to be like him.', NULL),
  (8423, 221, 'If I felt that I belonged someplace...', NULL),
  (8424, 221, 'It''s easier sometimes than talking to your folks.', NULL),
  (8425, 221, 'Jim, your eggs are on the table, dear.', NULL),
  (8426, 221, 'I couldn''t swallow until recess.', NULL),
  (8427, 221, 'Young fellow, you knock them dead like your old man used to.', NULL),
  (8428, 221, 'You don''t have to be unfriendly.', NULL),
  (8429, 221, 'Hey, which way to University and Tenth?', NULL),
  (8430, 221, 'You stepped on the school insignia.', NULL),
  (8431, 221, 'The last of us search the heavens and stand amazed.', NULL),
  (8432, 221, 'It''s hard to make friends with these guys.', NULL),
  (8433, 221, 'May I please have your attention?', NULL),
  (8434, 221, 'I told you not to fool with those guys.', NULL),
  (8435, 221, 'You read too many comic books.', NULL),
  (8436, 221, 'Now, you understand the action?', NULL),
  (8437, 221, 'Cut off a button and you get to join the club.', NULL),
  (8438, 221, 'Now, you say the word and you''re dead.', NULL),
  (8439, 221, 'Hey, Buzz, that''s dangerous up there.', NULL),
  (8440, 221, 'What''s the matter with the nice man?', NULL),
  (8441, 221, 'Haven''t you forgotten something?', NULL),
  (8442, 221, 'I didn''t kiss her, so it''s a big thing.', NULL),
  (8443, 221, 'Sit down and have your tomato juice.', NULL),
  (8444, 221, 'Girls your age don''t do things like that!', NULL),
  (8445, 221, 'It''s just the age when nothing fits.', NULL),
  (8446, 221, 'Well, I wouldn''t make a hasty decision.', NULL),
  (8447, 221, 'The kind I was telling you about.', NULL),
  (8448, 221, 'And then if we''re still stuck...', NULL),
  (8449, 221, 'Are you going to keep me from going?', NULL),
  (8450, 221, 'Listen, Jimbo, I''m just trying to show you how foolish you are.', NULL),
  (8451, 221, 'It happened to me when I was your age, maybe a year older.', NULL),
  (8452, 221, 'I guess it''s just my morbid personality.', NULL),
  (8453, 221, 'But when he does, you know he means it.', NULL),
  (8454, 221, 'It''s really James, but he likes Jim more.', NULL),
  (8455, 221, 'I don''t have too many people I can talk to.', NULL),
  (8456, 221, 'I''ll see you in the morning, okay?', NULL),
  (8457, 221, 'You better give me an answer this time.', NULL),
  (8458, 221, 'You wanted him to make a list!', NULL),
  (8459, 221, 'I said it was a matter of honor.', NULL),
  (8460, 221, 'I can''t keep it to myself anymore.', NULL),
  (8461, 221, 'I''ve been going around with my head in a sling for years.', NULL),
  (8462, 221, 'You''re involved in this, just like I am!', NULL),
  (8463, 221, 'Do we have to listen to a sermon now?', NULL),
  (8464, 221, 'No, I don''t want you to go to the police.', NULL),
  (8465, 221, 'I can''t get out of it and pretend it didn''t happen!', NULL),
  (8466, 221, 'Well, I don''t think that I want to learn that way.', NULL),
  (8467, 221, 'When you can''t face yourself you blame me!', NULL),
  (8468, 221, 'Once, I want to do something right!', NULL),
  (8469, 221, 'A foolish decision now could wreck your whole life!', NULL),
  (8470, 221, 'You want to kill your own father?', NULL),
  (8471, 221, 'This place appeal to you or something?', NULL),
  (8472, 221, 'What, are you out of your mind?', NULL),
  (8473, 221, 'Have you ever been booked before?', NULL),
  (8474, 221, 'Jim, this is dedicated to you...', NULL),
  (8475, 221, 'I woke up this morning, you know?', NULL),
  (8476, 221, 'I''m sorry that I treated you mean today.', NULL),
  (8477, 221, 'It''s an old, deserted mansion...', NULL),
  (8478, 221, 'At first I thought it was Jim...', NULL),
  (8479, 221, 'Where''s your baby boy gone to?', NULL),
  (8480, 221, 'What do you think of my castle?', NULL),
  (8481, 221, 'I''ll scrimp and save and work my fingers to the bone.', NULL),
  (8482, 221, 'I don''t know what to do when they cry.', NULL),
  (8483, 221, 'In fact, if you lock them in, you''ll never have to see them again.', NULL),
  (8484, 221, 'Let''s see how long we can stay under.', NULL),
  (8485, 221, 'What''d you come back here for?', NULL),
  (8486, 221, 'I can''t even remember what happened yesterday.', NULL),
  (8487, 221, 'I wonder how many rooms in this place?', NULL),
  (8488, 221, 'What kind of a person do you think a girl wants?', NULL),
  (8489, 221, 'We just zeroed gray Ford coupe, 1946.', NULL),
  (8490, 221, 'You should have heard him tonight.', NULL),
  (8491, 221, 'You''re making it tough on yourself, kid.', NULL),
  (8492, 221, 'My boy ran off and he got a gun too.', NULL),
  (8493, 221, 'Whoever you are, drop your weapon and come out.', NULL),
  (8494, 221, 'I''m going to open the door now.', NULL),
  (8495, 221, 'How can I talk to you if I can''t see you?', NULL),
  (8496, 221, 'I''m not going to hurt you or anything like that.', NULL),
  (8497, 221, 'Hey, now can I have the gun, Plato?', NULL),
  (8498, 221, 'You know, every one of them want to see that you''re safe.', NULL),
  (8499, 221, 'You want me to make them go away?', NULL),
  (8500, 221, 'When I saw that red jacket, I...', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (8901, 239, 'I''ve come to Grandma''s funeral.', NULL),
  (8902, 239, 'Well, if you gotta go, that''s the way to do it.', NULL),
  (8903, 239, 'Tonight''s the night, isn''t it?', NULL),
  (8904, 239, 'Tomorrow we''ll pay everyone something on account.', NULL),
  (8905, 239, 'I''m puttin'' you up for membership.', NULL),
  (8906, 239, 'Now we don''t have to worry about who to pay first.', NULL),
  (8907, 239, 'Tomorrow we''ll have 20 overcoats.', NULL),
  (8908, 239, 'There''s a dog running in the third.', NULL),
  (8909, 239, 'You''re makin'' it up pretty good so far.', NULL),
  (8910, 239, 'Here we are, packed and ready to leave for Miami, and what happens?', NULL),
  (8911, 239, 'I wonder if I''ve got room for another ulcer.', NULL),
  (8912, 239, 'We could borrow clothes from the chorus girls.', NULL),
  (8913, 239, 'You don''t have two girl musicians available, do you?', NULL),
  (8914, 239, 'We coulda had three weeks in Florida, all expenses paid.', NULL),
  (8915, 239, 'I just dropped in to pay my respects.', NULL),
  (8916, 239, 'We''re just a couple of musicians.', NULL),
  (8917, 239, 'We''d never live to testify against Spats Colombo.', NULL),
  (8918, 239, 'We''re not gonna get away with it, Joe.', NULL),
  (8919, 239, 'Are you two from the Poliakoff Agency?', NULL),
  (8920, 239, 'Take off your corsets and spread out.', NULL),
  (8921, 239, 'I was scared it was Sweet Sue.', NULL),
  (8922, 239, 'I play the ukulele, and I sing, too.', NULL),
  (8923, 239, 'But I''m the one that gets caught.', NULL),
  (8924, 239, 'Boy, would I love to borrow a cup of that Sugar.', NULL),
  (8925, 239, 'Didn''t you girls say you went to a conservatory?', NULL),
  (8926, 239, 'Just keep tellin'' yourself you''re a girl.', NULL),
  (8927, 239, 'I wanted to thank you for covering up for me.', NULL),
  (8928, 239, 'I can think of a million things.', NULL),
  (8929, 239, 'We''d cuddle up under the covers and pretend we were lost in a dark cave and were trying to find our way out.', NULL),
  (8930, 239, 'Dolores, do you still have that vermouth?', NULL),
  (8931, 239, 'Could you use some Southern Comfort?', NULL),
  (8932, 239, 'What''s the matter with you, anyway?', NULL),
  (8933, 239, 'I worked with six in the last two years.', NULL),
  (8934, 239, 'You don''t know what they''re like.', NULL),
  (8935, 239, 'It''s the same thing all over again.', NULL),
  (8936, 239, 'That''s why I''m glad we''re going to Florida.', NULL),
  (8937, 239, 'All right, what''s goin'' on around here?', NULL),
  (8938, 239, 'If there''s one thing I admire, it''s a girl with a shapely ankle.', NULL),
  (8939, 239, 'So when George White''s Scandals opened, she packed me off to Florida.', NULL),
  (8940, 239, 'She doesn''t approve of girls who smoke.', NULL),
  (8941, 239, 'But don''t worry about it, Sugar.', NULL),
  (8942, 239, 'You''re gonna meet a millionaire - a young one.', NULL),
  (8943, 239, 'Oh, you wanna see my driver''s licence?', NULL),
  (8944, 239, 'Would you rather be picking lead out of your navel?', NULL),
  (8945, 239, 'And I''m gonna keep an eye on you.', NULL),
  (8946, 239, 'She''ll rub it on me, I''ll rub it on her, we''ll rub it on each other.', NULL),
  (8947, 239, 'It''s carrying that bull fiddle around.', NULL),
  (8948, 239, 'I won''t sue you, no matter who you are.', NULL),
  (8949, 239, 'Look, if you''re interested in whether I am married or not...', NULL),
  (8950, 239, 'I personally prefer classical music.', NULL),
  (8951, 239, 'I''ll bet you''re also gentle and helpless.', NULL),
  (8952, 239, 'It''s on account of these shells.', NULL),
  (8953, 239, 'We have to be very careful whom we pick for a roommate.', NULL),
  (8954, 239, 'I can''t wait to tell Josephine.', NULL),
  (8955, 239, 'Well, he''s young and he''s handsome.', NULL),
  (8956, 239, 'What does your crystal ball say?', NULL),
  (8957, 239, 'I''m gonna press the suit myself.', NULL),
  (8958, 239, 'There''s gonna be a full moon tonight.', NULL),
  (8959, 239, 'You''re gonna be on the boat with that dirty old man?', NULL),
  (8960, 239, 'Why do I let you talk me into these things?', NULL),
  (8961, 239, 'You know how those millionaires are.', NULL),
  (8962, 239, 'This is Sweet Sue saying good night, reminding all you daddies out there that every girl in my band is a virtuoso.', NULL),
  (8963, 239, 'I wanted them to fly orchids from our greenhouse, but Long lsland is fogged in.', NULL),
  (8964, 239, 'My dad''s more interested in railroads.', NULL),
  (8965, 239, 'You have an upstairs and a downstairs.', NULL),
  (8966, 239, 'Isn''t it amazing how they get those big fish into those little glass jars?', NULL),
  (8967, 239, 'You see, on Thursdays I''m sort of lost around here.', NULL),
  (8968, 239, 'Well, it''s more like a mental block.', NULL),
  (8969, 239, 'It was my freshman year at Princeton.', NULL),
  (8970, 239, 'All the money in the world, and what good is it?', NULL),
  (8971, 239, 'If I wasn''t such a coward, I''d kill myself.', NULL),
  (8972, 239, 'It''s like taking someone to a concert when he''s tone-deaf.', NULL),
  (8973, 239, 'Your glasses are beginning to steam up.', NULL),
  (8974, 239, 'Tomorrow, remind me to send a cheque for $100,000 to the Milk Fund.', NULL),
  (8975, 239, 'Do you think he''s too old for me?', NULL),
  (8976, 239, 'Jerry, you''re outta your mind.', NULL),
  (8977, 239, 'Just keep telling yourself you''re a boy.', NULL),
  (8978, 239, 'I think he''s going to propose.', NULL),
  (8979, 239, 'All right, Spats, get your hands up.', NULL),
  (8980, 239, 'Thought I''d come in case anybody decided to sing.', NULL),
  (8981, 239, 'You vulcanised Toothpick Charlie, and we know it.', NULL),
  (8982, 239, 'I feel like such a tramp, taking jewellery from a man under false pretences.', NULL),
  (8983, 239, 'Something tells me the omelette is about to hit the fan.', NULL),
  (8984, 239, 'They''re gonna line us up against the wall and...', NULL),
  (8985, 239, 'If we get outta the hotel alive.', NULL),
  (8986, 239, 'I was still on the yacht and the anchor broke loose.', NULL),
  (8987, 239, 'You see, we have these oil interests in Venezuela.', NULL),
  (8988, 239, 'I only wish there was something I could do for you.', NULL),
  (8989, 239, 'I haven''t had white orchids since I was a debutante.', NULL),
  (8990, 239, 'You''re not pullin'' one of your old tricks.', NULL),
  (8991, 239, 'He''s the first nice guy I''ve met in my life.', NULL),
  (8992, 239, 'We don''t wanna run into Spats and his chums.', NULL),
  (8993, 239, 'Maybe those dames ain''t dames.', NULL),
  (8994, 239, 'It''s been ten years since I elected myself president of this organisation, and, if I say so myself, you made the right choice.', NULL),
  (8995, 239, 'I promised to bring back a piece to my kids.', NULL),
  (8996, 239, 'Some people say he''s gone too far.', NULL),
  (8997, 239, 'Some people would say that''s real sloppy.', NULL),
  (8998, 239, 'There was somethin'' in that cake that didn''t agree with ''em.', NULL),
  (8999, 239, 'Tell him you''re gonna elope with him.', NULL),
  (9000, 239, 'One of those no-goodniks you keep running away from.', NULL),
  (13701, 381, 'Monsieur Robie, we represent the Sret.', NULL),
  (13702, 381, 'I haven''t stolen a piece ofjewelry in 1 5 years.', NULL),
  (13703, 381, 'But since the war, I have obliged all these men to be honest.', NULL),
  (13704, 381, 'I wouldn''t put it past any of them to be doing the robberies themselves.', NULL),
  (13705, 381, 'Well, no one believes me, but the police are chasing the wrong man.', NULL),
  (13706, 381, 'To catch him in the act, I need better information than he has, the kind that takes months to dig out.', NULL),
  (13707, 381, 'Then he asked me about the jewels my clients wear, and I said to myself, "You have something to do with this new Cat.', NULL),
  (13708, 381, 'That you never asked me to marry you?', NULL),
  (13709, 381, 'I work for a living, too, raising grapes and flowers.', NULL),
  (13710, 381, 'Together with your father and the rest of my old Resistance pals.', NULL),
  (13711, 381, 'Well, at least they haven''t been withdrawn from circulation.', NULL),
  (13712, 381, 'And I thought you hoped to be inconspicuous.', NULL),
  (13713, 381, 'Yes, let''s just say betting, because I have a long shot for you.', NULL),
  (13714, 381, 'And you don''t think they''d approve of your giving me a list of your richest clients.', NULL),
  (13715, 381, 'They could put me away for good.', NULL),
  (13716, 381, 'Oh, the addresses, habits, whatever you''ve got.', NULL),
  (13717, 381, 'He hasn''t left the villa in years.', NULL),
  (13718, 381, 'Now, it''s a very nice custom they have here in France, provisional liberty based upon insufficient evidence.', NULL),
  (13719, 381, 'Oh, to live better, to own things I couldn''t afford.', NULL),
  (13720, 381, 'Well, for what it''s worth, I only stole from people who wouldn''t go hungry.', NULL),
  (13721, 381, 'Now, are you going to deduct the price of a lunch from your expense account?', NULL),
  (13722, 381, 'And someday you''re going to be sorry that you didn''t deduct this lunch from your expense account.', NULL),
  (13723, 381, 'You don''t have to spend every day of your life proving your honesty, but I do.', NULL),
  (13724, 381, 'Come on, Hughson, you''re wasting time.', NULL),
  (13725, 381, 'Stevens, wouldn''t it perhaps be better if you left some of that jewelry in the hotel safe?', NULL),
  (13726, 381, 'Mother, everywhere you go, you complain about tipping.', NULL),
  (13727, 381, 'Hughson doesn''t care for gambling.', NULL),
  (13728, 381, 'I should never have stopped here.', NULL),
  (13729, 381, 'But he''d think all this flying around from Palm Springs to Saint Moritz to the Riviera...', NULL),
  (13730, 381, 'A man with both feet on the ground, that''s what he was.', NULL),
  (13731, 381, 'Burns, would you call me Jessie?', NULL),
  (13732, 381, 'I think they finished her there.', NULL),
  (13733, 381, 'Burns, do you make much money at lumber?', NULL),
  (13734, 381, 'To meet someone as charming as you.', NULL),
  (13735, 381, 'Well, at least you know that the...', NULL),
  (13736, 381, 'They''re pretty and they attract attention.', NULL),
  (13737, 381, 'Well, I''ll get my bathing trunks.', NULL),
  (13738, 381, 'He gave me a list of furnished villas for rent.', NULL),
  (13739, 381, 'Last night you steal a small fortune, and today you lie on the beach with an American beauty.', NULL),
  (13740, 381, 'Well, it''s nice to know I have friends.', NULL),
  (13741, 381, 'Then don''t you think it''s foolish to remain here without knowing what will happen to you?', NULL),
  (13742, 381, 'Another robbery and they will do something to you.', NULL),
  (13743, 381, 'Oh, you didn''t tell me your name.', NULL),
  (13744, 381, 'Would you like me to teach you how to water ski?', NULL),
  (13745, 381, 'You know what I''d like to tell you, don''t you?', NULL),
  (13746, 381, 'I have my car, and a basket lunch with chicken and beer.', NULL),
  (13747, 381, 'Well, I guess I can''t seem to get out of this gracefully, so let''s go.', NULL),
  (13748, 381, 'When I was 1 0, my father died and they discovered oil on our land, and that''s when I really started to travel.', NULL),
  (13749, 381, 'Yes, I will say you do things with dispatch.', NULL),
  (13750, 381, 'That''s a routine compliment, but I''ll accept it.', NULL),
  (13751, 381, 'Give me a woman who knows her own mind.', NULL),
  (13752, 381, 'Why don''t you own a place like this?', NULL),
  (13753, 381, 'I''d rather spend my money on more tangible excitement.', NULL),
  (13754, 381, 'Mediterranean, turn of the century, isn''t it?', NULL),
  (13755, 381, 'Oh, I''ll bet you snowed her under.', NULL),
  (13756, 381, 'Not till we get to the picnic grounds.', NULL),
  (13757, 381, 'I don''t know what you''re talking about.', NULL),
  (13758, 381, 'You may have read about somebody called the Cat, but...', NULL),
  (13759, 381, 'Well, the first thing I noticed about you was...', NULL),
  (13760, 381, 'Oh, now, don''t be disappointing and sound like Mr.', NULL),
  (13761, 381, 'Well, she did, because I liked her.', NULL),
  (13762, 381, 'Otherwise you never would have let me say good night so easily.', NULL),
  (13763, 381, 'Don''t you know that all the guidebooks say, "Don''t behave like a tourist"?', NULL),
  (13764, 381, 'Oh, I don''t know, about four or five days.', NULL),
  (13765, 381, 'I know every inch of her villa.', NULL),
  (13766, 381, 'That villa we went to isn''t for rent, and you know it.', NULL),
  (13767, 381, 'You''ll get a better view from my place.', NULL),
  (13768, 381, 'I do not ask you what you were doing there.', NULL),
  (13769, 381, 'You bring her to my restaurant for dinner, yes?', NULL),
  (13770, 381, 'You''ve been dying to say something about it all evening.', NULL),
  (13771, 381, 'And you''re over the roofs in the darkness, down the side wall to the right apartment, and the window''s locked.', NULL),
  (13772, 381, 'Hold this necklace in your hand and tell me you''re not John Robie, the Cat.', NULL),
  (13773, 381, 'My only comment would be highly censurable.', NULL),
  (13774, 381, 'Just as long as you''re satisfied.', NULL),
  (13775, 381, 'Well, that doesn''t make sense.', NULL),
  (13776, 381, 'Oh, I''m a little tired of draping those things over me.', NULL),
  (13777, 381, 'Somehow, I can''t get worked up over it.', NULL),
  (13778, 381, 'But there aren''t any clues to cover up.', NULL),
  (13779, 381, 'Listen to what it says about us.', NULL),
  (13780, 381, 'Why do you think we moved so many times?', NULL),
  (13781, 381, 'They were my baubles that were stolen.', NULL),
  (13782, 381, 'Oh, Mother, he played us both for fools, and you know it.', NULL),
  (13783, 381, 'Do you still believe I did the Stevens job?', NULL),
  (13784, 381, 'I''ve seen him in the dark, but I haven''t managed to get close enough to catch him and to find out who it is.', NULL),
  (13785, 381, 'Someone wants you to go to the Silvas'' tonight.', NULL),
  (13786, 381, 'You are positive Foussard was the Cat?', NULL),
  (13787, 381, 'Now, I''m disinclined to do this if recovery of the jewelry is imminent.', NULL),
  (13788, 381, 'Yes, you showed such good taste in keeping it out of the newspapers.', NULL),
  (13789, 381, 'Lepic, that''s all I wanted to know.', NULL),
  (13790, 381, 'You know, for risking the prison to capture the Cat.', NULL),
  (13791, 381, 'Let''s talk about it at the Sanford gala over the weekend, you know, between your catering duties.', NULL),
  (13792, 381, 'Because I was getting too close to the Cat.', NULL),
  (13793, 381, 'You might possibly be wrong about me.', NULL),
  (13794, 381, 'I''ll make you a sporting, exciting offer.', NULL),
  (13795, 381, 'Oh, you probably wonder why I want to go, huh?', NULL),
  (13796, 381, 'Would you be a sweetie, John, and go and get them for me?', NULL),
  (13797, 381, 'He couldn''t climb anything, and you always did his legwork for him, even during the war when you were a kid.', NULL),
  (13798, 381, 'GUN FlRlNG) HUGHSON: He''s not alone up there.', NULL),
  (13799, 381, 'We''re telling them down there, remember?', NULL),
  (13800, 381, 'And we would have caught you, too, if my dress hadn''t gotten caught all over the steering wheel and gearshift.', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (13901, 389, 'To continue, you''ve listened to a long and complex case, murder in the first degree.', NULL),
  (13902, 389, 'However you decide, your verdict must be unanimous.', NULL),
  (13903, 389, 'I thought we might wanna vote by ballot.', NULL),
  (13904, 389, 'We can start with a five-minute break.', NULL),
  (13905, 389, 'If you had to sort out all that junk, like that thing with the movies.', NULL),
  (13906, 389, 'You got a seat on the exchange?', NULL),
  (13907, 389, 'It''s reasonable to sit in order.', NULL),
  (13908, 389, 'Who have they got besides good groundkeepers?', NULL),
  (13909, 389, 'Maybe we can all get outta here.', NULL),
  (13910, 389, 'Would you like me to list ''em for you?', NULL),
  (13911, 389, 'Couldn''t change my mind if you talked for 100 years.', NULL),
  (13912, 389, 'The ball game doesn''t start till eight o''clock.', NULL),
  (13913, 389, 'I think we owe him a few words, that''s all.', NULL),
  (13914, 389, 'I''ve lived among them all my life.', NULL),
  (13915, 389, 'We might be able to show you where you''re mixed up.', NULL),
  (13916, 389, 'I mean, somebody saw him do it.', NULL),
  (13917, 389, 'He claimed he was at the movies, yet he couldn''t remember the names of the films he saw or who played in them.', NULL),
  (13918, 389, 'How come you believe the woman?', NULL),
  (13919, 389, 'Didn''t they say something about a fight, an argument, between the old man and his son around about seven o''clock that night?', NULL),
  (13920, 389, 'He''s been arrested for muggin''.', NULL),
  (13921, 389, 'I said "I''m gonna make a man out of you if I have to break you in two tryin''.', NULL),
  (13922, 389, 'It''s no secret that children from slums are potential menaces to society.', NULL),
  (13923, 389, 'He''s the one keeping us in here.', NULL),
  (13924, 389, 'Here, you take on the responsibility.', NULL),
  (13925, 389, 'I sat there in court for six days listening while the evidence built up.', NULL),
  (13926, 389, 'When they don''t ask questions, it''s because they know the answers already.', NULL),
  (13927, 389, 'What about the switch knife they found in the old man''s chest?', NULL),
  (13928, 389, 'The knife and the way it was bought is strong evidence, don''t you think?', NULL),
  (13929, 389, 'I''m just saying a coincidence is possible.', NULL),
  (13930, 389, 'Now supposing you tell me what it proves.', NULL),
  (13931, 389, 'If you wanna hang this jury, go ahead.', NULL),
  (13932, 389, 'I don''t see what the knife has got to do with anything.', NULL),
  (13933, 389, 'I''m going to call for another vote.', NULL),
  (13934, 389, 'Brother, you really are somethin''.', NULL),
  (13935, 389, 'What made you change your vote?', NULL),
  (13936, 389, 'It''s not easy to stand alone against the ridicule of others.', NULL),
  (13937, 389, 'Wish I could figure out some way we could break it up.', NULL),
  (13938, 389, 'I''m telling him, in an ad agency when a point like this is reached in a meeting, there''s always some character ready with an idea, see.', NULL),
  (13939, 389, 'Well, you''ve got it, believe me.', NULL),
  (13940, 389, 'Or did somebody bump you on the head once and you haven''t gotten over it?', NULL),
  (13941, 389, 'So why don''t we stop wastin'' our time here?', NULL),
  (13942, 389, 'You think he''s not guilty, huh?', NULL),
  (13943, 389, 'The old man who lived downstairs says he heard the kid yell "I''m gonna kill ya.', NULL),
  (13944, 389, 'You can reach out and almost touch the el tracks, right?', NULL),
  (13945, 389, 'We''ve agreed that it takes ten seconds for a train to pass a given point.', NULL),
  (13946, 389, 'Maybe he didn''t, with all that el noise.', NULL),
  (13947, 389, 'Why do you think the old man might lie?', NULL),
  (13948, 389, 'That''s the most fantastic story ever.', NULL),
  (13949, 389, 'This phrase, how many times have all of us used it?', NULL),
  (13950, 389, 'I was arguing with the guy I work next to at the bank a few weeks ago.', NULL),
  (13951, 389, 'He doesn''t even speak good English.', NULL),
  (13952, 389, 'The kid had a lawyer, didn''t he?', NULL),
  (13953, 389, 'I have been listening very carefully and...', NULL),
  (13954, 389, 'It''s not nice to leave knives in people''s chests.', NULL),
  (13955, 389, 'I don''t believe I have to be loyal to one side or the other.', NULL),
  (13956, 389, 'Didn''t hear the scream, did run out in a panic, calmed down later and came back for the knife, risking being caught by the police.', NULL),
  (13957, 389, 'You''re talking about little details and forgetting the important stuff.', NULL),
  (13958, 389, 'Why don''t you listen to the facts?', NULL),
  (13959, 389, 'That''s not the knife, remember?', NULL),
  (13960, 389, 'Did the old man say he ran to the door?', NULL),
  (13961, 389, 'No, but I''d like to know if an old man who drags one foot cos he had a stroke can get from his bedroom to his front door in 15 seconds.', NULL),
  (13962, 389, 'You oughta be at that hair-splitters'' convention.', NULL),
  (13963, 389, 'Maybe he just didn''t think of it.', NULL),
  (13964, 389, 'According to you, it''ll only take Come on.', NULL),
  (13965, 389, 'When he''s in bed, he heard the body hit the floor, heard the woman scream, got to his front door as fast as he could, heard somebody running and assumed it was the boy.', NULL),
  (13966, 389, 'What''s the matter with you guys?', NULL),
  (13967, 389, 'You don''t really mean you''ll kill me, do you?', NULL),
  (13968, 389, 'That we are notified by mail to come down to this place to decide on the guilt or innocence of a man we...', NULL),
  (13969, 389, 'Maybe we can follow this one up with a little dancing and refreshments!', NULL),
  (13970, 389, 'You can twist ''em any way you like.', NULL),
  (13971, 389, 'You think too much, you get mixed up.', NULL),
  (13972, 389, 'I''m the assistant head coach at Andrew J McCorkle High School.', NULL),
  (13973, 389, 'Where does he come off calling me a public avenger, a sadist?', NULL),
  (13974, 389, 'This kid wouldn''t stand a chance with another jury, and you know it.', NULL),
  (13975, 389, 'Let''s stop the arguing for about two minutes in here.', NULL),
  (13976, 389, 'The boy couldn''t remember the movies because he wasn''t there.', NULL),
  (13977, 389, 'When you get to New Year''s Eve 1954, let me know.', NULL),
  (13978, 389, 'Say, could I see that knife a second, please?', NULL),
  (13979, 389, 'I know, but I don''t go along with it.', NULL),
  (13980, 389, 'Now, this is the way I''d stab a man who was...', NULL),
  (13981, 389, 'Anyone who''s ever used one wouldn''t handle it any other way.', NULL),
  (13982, 389, 'What are you giving us this mumbo jumbo for?', NULL),
  (13983, 389, 'You have sat here and voted guilty with everyone else because there are some baseball tickets burning a hole in your pocket.', NULL),
  (13984, 389, 'Or don''t you have the guts to do what you think is right?', NULL),
  (13985, 389, 'You saw this kid just like I did.', NULL),
  (13986, 389, 'That''s the way they are by nature.', NULL),
  (13987, 389, 'You''re making a big mistake, you people.', NULL),
  (13988, 389, 'Wherever you run into it, prejudice always obscures the truth.', NULL),
  (13989, 389, 'And that''s something that''s very valuable in our system.', NULL),
  (13990, 389, 'As far as I can see it, this is unshakeable testimony.', NULL),
  (13991, 389, 'You, you''re the leader of the cause.', NULL),
  (13992, 389, 'I feel perfectly well, thank you.', NULL),
  (13993, 389, 'I''m sure you''ll pardon me for this, but I was wondering why you rub your nose like that.', NULL),
  (13994, 389, 'Your eyeglasses made those two deep impressions on the sides of your nose.', NULL),
  (13995, 389, 'Could those marks be made by anything other than eyeglasses?', NULL),
  (13996, 389, 'Ever see a woman who didn''t want to wear them because they spoil her looks?', NULL),
  (13997, 389, 'I only know the woman''s eyesight is in question now.', NULL),
  (13998, 389, 'I don''t care whether I''m alone or not.', NULL),
  (13999, 389, 'You can''t prove he didn''t get to the door!', NULL),
  (14000, 389, 'This business with the glasses?', NULL),
  (15301, 426, 'I thought you said no more aches or pains.', NULL),
  (15302, 426, 'I''ll throw this miserable thing out the window.', NULL),
  (15303, 426, 'You sound so disapproving, Midge.', NULL),
  (15304, 426, 'That''s what everybody tells me.', NULL),
  (15305, 426, 'You''ve got it, and there''s no losing it.', NULL),
  (15306, 426, 'Don''t forget, I''m a man of independent means, as the saying goes.', NULL),
  (15307, 426, 'I''ve never run across one like that.', NULL),
  (15308, 426, 'We were engaged once, weren''t we?', NULL),
  (15309, 426, 'He''s probably on the bum and wants to touch you for the price of a drink.', NULL),
  (15310, 426, 'He said that only another emotional shock could do it and probably wouldn''t.', NULL),
  (15311, 426, 'All right, here''s the first step.', NULL),
  (15312, 426, 'You don''t have to do it for a living.', NULL),
  (15313, 426, 'Shouldn''t you be sitting down?', NULL),
  (15314, 426, 'I guess that covers everything, doesn''t it?', NULL),
  (15315, 426, 'I''m afraid some harm may come to her.', NULL),
  (15316, 426, 'I''d have him check on you, too.', NULL),
  (15317, 426, 'Do you think I''m making it up?', NULL),
  (15318, 426, 'Then, with a long sigh, she''s back.', NULL),
  (15319, 426, 'When I got home that evening, I asked her what she''d done all day.', NULL),
  (15320, 426, 'Have you discussed this with the doctors?', NULL),
  (15321, 426, 'Scottie, I need a friend, someone I can trust.', NULL),
  (15322, 426, 'Say, will you tell me something?', NULL),
  (15323, 426, 'I''m afraid we couldn''t give out information of that sort.', NULL),
  (15324, 426, 'I can''t imagine that sweet girl-- What''s her name?', NULL),
  (15325, 426, 'But she hasn''t been here today.', NULL),
  (15326, 426, 'Would you please go up and look?', NULL),
  (15327, 426, 'Just, ''"Do you know an authority on San Francisco--''" Want a drink?', NULL),
  (15328, 426, 'I want to know who shot who in the Embarcadero in August, 1879.', NULL),
  (15329, 426, 'Have you seen my child?''" Poor thing.', NULL),
  (15330, 426, 'Who''s the guy and who''s the wife?', NULL),
  (15331, 426, 'There are things you didn''t tell me.', NULL),
  (15332, 426, 'Now when she''s alone, she takes them out and looks at them...', NULL),
  (15333, 426, 'When she goes to these places-- She''s no longer my wife.', NULL),
  (15334, 426, 'Why wouldn''t she tell her daughter?', NULL),
  (15335, 426, 'Your things are in the kitchen.', NULL),
  (15336, 426, 'I fell into the Bay and you fished me out?', NULL),
  (15337, 426, 'You''re terribly direct in your questions.', NULL),
  (15338, 426, 'Yes, that''s a lovely spot, isn''t it?', NULL),
  (15339, 426, 'There were some pins in my hair.', NULL),
  (15340, 426, 'But you didn''t know my car, did you?', NULL),
  (15341, 426, 'Do your friends call you John or Jack?', NULL),
  (15342, 426, 'Has this ever happened to you before?', NULL),
  (15343, 426, 'But I''ve never fallen into San Francisco Bay.', NULL),
  (15344, 426, 'There''s nothing to worry about.', NULL),
  (15345, 426, 'Well, I suddenly felt such a fool.', NULL),
  (15346, 426, 'You''ve nothing to apologize for.', NULL),
  (15347, 426, 'That''s the first time I''ve been grateful for Coit Tower.', NULL),
  (15348, 426, 'Don''t you think it''s a waste for the two of us....', NULL),
  (15349, 426, 'Always green, ever living.''" I don''t like them.', NULL),
  (15350, 426, 'What was inside that told you to jump?', NULL),
  (15351, 426, 'It''s as though I were walking down a long corridor...', NULL),
  (15352, 426, 'You didn''t know where you were.', NULL),
  (15353, 426, 'No, it''s new and clean and waiting.', NULL),
  (15354, 426, 'There''s someone within me, and she says I must die.', NULL),
  (15355, 426, 'What was this desperate urge to see me?', NULL),
  (15356, 426, 'What''ll we talk about at dinner?', NULL),
  (15357, 426, 'I always said you were wasting your time in the underwear department.', NULL),
  (15358, 426, 'I should have phoned, but I wanted to see you, be with you.', NULL),
  (15359, 426, 'A hundred miles south of San Francisco, there''s an old Spanish mission...', NULL),
  (15360, 426, 'You''ve given me something to work on now.', NULL),
  (15361, 426, 'You''ll come back here around noon.', NULL),
  (15362, 426, 'There''s an answer for everything.', NULL),
  (15363, 426, 'As you have learned, it was an unfortunate choice.', NULL),
  (15364, 426, 'That has nothing to do with your verdict.', NULL),
  (15365, 426, 'I shouldn''t have got you involved.', NULL),
  (15366, 426, 'And I probably never will come back.', NULL),
  (15367, 426, 'I had a long talk with that lady in Musical Therapy...', NULL),
  (15368, 426, 'You don''t even know I''m here, do you?', NULL),
  (15369, 426, 'We know little of what went on before.', NULL),
  (15370, 426, 'And you want to know something?', NULL),
  (15371, 426, 'Is it true that she really-- I''m sorry.', NULL),
  (15372, 426, 'You''ve got a nerve, following me into the hotel and up to my room.', NULL),
  (15373, 426, 'Then you saw me and something clicked.', NULL),
  (15374, 426, 'It''s a place to live, that''s all.', NULL),
  (15375, 426, 'My gosh, do I have to prove it?', NULL),
  (15376, 426, 'You have got it bad, haven''t you?', NULL),
  (15377, 426, 'I feel I owe you something after all this.', NULL),
  (15378, 426, 'Give me time to change and get fixed up.', NULL),
  (15379, 426, 'I want you to have peace of mind.', NULL),
  (15380, 426, 'He chose you to be the witness to a suicide.', NULL),
  (15381, 426, 'I don''t know whether I have the nerve to try.', NULL),
  (15382, 426, 'I''ve been understanding since I was 17.', NULL),
  (15383, 426, 'We''ll get this, then we''ll buy you those clothes.', NULL),
  (15384, 426, 'I think I know the suit you mean.', NULL),
  (15385, 426, 'I just want to see-- I don''t want any clothes.', NULL),
  (15386, 426, 'You certainly do know what you want, sir.', NULL),
  (15387, 426, 'You don''t even want to touch me.', NULL),
  (15388, 426, 'I''ll wear the darned clothes if you want me to...', NULL),
  (15389, 426, 'She''ll join you when she''s finished.', NULL),
  (15390, 426, 'You have a thing about Ernie''s, don''t you?', NULL),
  (15391, 426, 'Scottie, I do have you now, don''t I?', NULL),
  (15392, 426, 'I have to go back into the past once more.', NULL),
  (15393, 426, 'I have to tell you about Madeleine now.', NULL),
  (15394, 426, 'I couldn''t find her, and then I heard footsteps on the stairs.', NULL),
  (15395, 426, 'You''re my second chance, Judy.', NULL),
  (15396, 426, 'You were the counterfeit, weren''t you?', NULL),
  (15397, 426, 'Why did you scream, since you tricked me so well up to then?', NULL),
  (15398, 426, 'I''ll bet you''re a wonderful swimmer, aren''t you?', NULL),
  (15399, 426, 'We''re going up and look at the scene of the crime.', NULL),
  (15400, 426, 'You shouldn''t have been that sentimental.', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (17701, 521, 'Mark, before Tony comes, I ought to explain something.', NULL),
  (17702, 521, 'When you get to know Tony, you''ll understand why I said that.', NULL),
  (17703, 521, 'But he''s been wonderful ever since.', NULL),
  (17704, 521, 'I recovered the handbag about two weeks later...', NULL),
  (17705, 521, 'I can''t understand why you didn''t tell me.', NULL),
  (17706, 521, 'I believe you''d have done it then.', NULL),
  (17707, 521, 'How do you like it over here, Mark?.', NULL),
  (17708, 521, 'I shall have to fake half of it as it is.', NULL),
  (17709, 521, 'We''re giving them a farewell dinner.', NULL),
  (17710, 521, 'It certainly looks just the job for me.', NULL),
  (17711, 521, 'You might bring the registration book and any necessary papers.', NULL),
  (17712, 521, 'Well, you''ve got a better memory than I have.', NULL),
  (17713, 521, 'I say, it is for sale, isn''t it?.', NULL),
  (17714, 521, 'Wait a minute, I think I have a picture of you here somewhere.', NULL),
  (17715, 521, 'I''d left it in a cashbox in my study, and in the morning, it had gone.', NULL),
  (17716, 521, 'I''m almost resigned to living on what I can earn.', NULL),
  (17717, 521, 'I went alone to America for the grass-court season...', NULL),
  (17718, 521, 'I parked the car two streets away, walked back in my tracks.', NULL),
  (17719, 521, 'I can''t ever remember being so scared.', NULL),
  (17720, 521, 'I didn''t go to that tournament after all.', NULL),
  (17721, 521, 'But it didn''t, so I kept the letter.', NULL),
  (17722, 521, 'And the fellows were talking about you.', NULL),
  (17723, 521, 'It was when I saw you in that pub that it happened.', NULL),
  (17724, 521, 'I''ve been following you ever since.', NULL),
  (17725, 521, 'You''d changed your name to Adams.', NULL),
  (17726, 521, 'I suppose she thought you were growing that handsome mustache to please her.', NULL),
  (17727, 521, 'Aren''t you forgetting something?.', NULL),
  (17728, 521, 'That would puzzle them, wouldn''t it.', NULL),
  (17729, 521, 'You see, I''m quite well-known.', NULL),
  (17730, 521, 'You were planning to marry Mrs.', NULL),
  (17731, 521, 'It''s in a small attach case in a checkroom.', NULL),
  (17732, 521, 'Your balance has dropped by over 1000 during the year.', NULL),
  (17733, 521, 'You''ll find the key to this door...', NULL),
  (17734, 521, 'Close the lid, but don''t snap the locks.', NULL),
  (17735, 521, 'You thought the apartment was empty, so you took the suitcase and went to work.', NULL),
  (17736, 521, 'How do I get in, in the first place?.', NULL),
  (17737, 521, 'When I come back with Halliday, I''ll use my own key to let us in.', NULL),
  (17738, 521, 'Look, why don''t you take Mark to Gerry''s.', NULL),
  (17739, 521, 'When are you going to finish pasting in those clippings?.', NULL),
  (17740, 521, 'I usually put myself in the criminal''s shoes and I keep asking myself: "What do I do next?.', NULL),
  (17741, 521, 'Are you sure yours isn''t in your overcoat?.', NULL),
  (17742, 521, 'You know I hate doing nothing.', NULL),
  (17743, 521, 'You don''t have to if you don''t want to, you know.', NULL),
  (17744, 521, 'Tony, what are you waiting for?.', NULL),
  (17745, 521, 'I was staying at the Torbay Hotel, as I was saying, I went to the bar....', NULL),
  (17746, 521, 'He put something around my throat.', NULL),
  (17747, 521, 'When will the police get here?.', NULL),
  (17748, 521, 'What do you mean, you don '' t know?.', NULL),
  (17749, 521, 'It always runs out just when we need it.', NULL),
  (17750, 521, 'I''m Chief Inspector Hubbard, in charge of Criminal Investigation of this division.', NULL),
  (17751, 521, 'We assume he must have come in through these windows here.', NULL),
  (17752, 521, 'At least, we''ve discovered where he lived.', NULL),
  (17753, 521, 'He''s very like someone I was at college with, but the mustache makes a difference.', NULL),
  (17754, 521, 'Did you switch this light on?.', NULL),
  (17755, 521, 'In case I have to write anything down, I can hold the phone in my left hand.', NULL),
  (17756, 521, 'No, inspector, I drew them just before I went out.', NULL),
  (17757, 521, 'I was trying to call to the police...', NULL),
  (17758, 521, 'Margot, did you open that door at all after we''d gone?.', NULL),
  (17759, 521, 'Remember when your bag was stolen?.', NULL),
  (17760, 521, 'Wasn''t that where you said you saw this man, sir?.', NULL),
  (17761, 521, 'We''d better get all this down on paper.', NULL),
  (17762, 521, 'Tony, I know what I wanted to ask you.', NULL),
  (17763, 521, 'You mean, you hauled me out of bed to get his number?.', NULL),
  (17764, 521, 'Your telephone number as well.', NULL),
  (17765, 521, 'I didn''t mention it because I wasn''t sure how much Mr.', NULL),
  (17766, 521, 'How many times have you seen this man?.', NULL),
  (17767, 521, 'Well, you say you did it in self-defense.', NULL),
  (17768, 521, 'Now, you suggest that this man came to burgle your flat.', NULL),
  (17769, 521, 'At present, that appears to be the only way he could''ve entered.', NULL),
  (17770, 521, 'Can you explain why your attacker should do that?.', NULL),
  (17771, 521, 'Could you come around at once, Maida Vale Police Station?.', NULL),
  (17772, 521, 'Now you say you did not know him.', NULL),
  (17773, 521, 'I really believe it''s her only chance.', NULL),
  (17774, 521, 'I''ve figured out something for you to tell them.', NULL),
  (17775, 521, 'Are you suggesting I arranged for Swan to come here...', NULL),
  (17776, 521, 'You see how it all hangs together?.', NULL),
  (17777, 521, 'Face it, they can''t hang you for a murder that never came off.', NULL),
  (17778, 521, 'For instance, how could I have persuaded Swan to do a thing like this?.', NULL),
  (17779, 521, 'I''m very conscious of your position.', NULL),
  (17780, 521, 'Yes, as a matter of fact, I have.', NULL),
  (17781, 521, 'That''s the trouble with these latchkeys, they''re all alike.', NULL),
  (17782, 521, 'It has been done before, you know.', NULL),
  (17783, 521, 'Have you a small, blue attach case?.', NULL),
  (17784, 521, 'Wendice has something to tell you.', NULL),
  (17785, 521, 'Apparently, I bribed Swan to murder my wife so that-- Correct me if I go wrong, Mark.', NULL),
  (17786, 521, 'He could''ve taken his key from Swan''s pocket before you got here.', NULL),
  (17787, 521, 'When she called me back from the party that night...', NULL),
  (17788, 521, 'Whenever I needed money, I took it out...', NULL),
  (17789, 521, 'You''d have to admit you arrested the wrong person.', NULL),
  (17790, 521, 'I don''t want her upset just now.', NULL),
  (17791, 521, 'Give me Sergeant O'' Brien, quick.', NULL),
  (17792, 521, 'May I have your bag a moment?.', NULL),
  (17793, 521, 'They said I could go, but I couldn''t get that door open.', NULL),
  (17794, 521, 'Shouldn''t I break down or something?.', NULL),
  (17795, 521, 'And I saw a copy of his bank statement in that desk.', NULL),
  (17796, 521, 'He just came back and couldn''t get in.', NULL),
  (17797, 521, 'He still thinks it''s in the handbag.', NULL),
  (17798, 521, 'I took the key that was in your handbag...', NULL),
  (17799, 521, 'As I''ve pinched his latchkey, he''ll try the one in the handbag.', NULL),
  (17800, 521, 'He''s looking at the handbag now.', NULL),
  (19330, 567, 'When you wake up in the morning, do you feel tired and rundown?', NULL),
  (19331, 567, 'Next Wednesday I emerge from this...', NULL),
  (19332, 567, 'There''s no point in even talking about it.', NULL),
  (19333, 567, 'I didn''t ask you to stand in the middle of an automobile racetrack.', NULL),
  (19334, 567, 'It''s about time you got married, before you turn into a lonesome and bitter, old man.', NULL),
  (19335, 567, 'You''re giving them far too much water.', NULL),
  (19336, 567, 'Well, I only quote from the best.', NULL),
  (19337, 567, 'I was nursing a director of General Motors.', NULL),
  (19338, 567, 'You say, "Judge, it was only a bit of innocent fun.', NULL),
  (19339, 567, 'How can you tell from a thermometer?', NULL),
  (19340, 567, 'I''m just not ready for marriage.', NULL),
  (19341, 567, 'No, she''s just not the girl for me.', NULL),
  (19342, 567, 'I''ll probably get married one of these days, but when I do, it''s gonna be to someone who thinks of life not just as a new dress and a lobster dinner and the latest scandal.', NULL),
  (19343, 567, 'Look, Mr Jefferies, I''m not an educated woman, but I can tell you one thing.', NULL),
  (19344, 567, 'Now, would you fix me a sandwich, please?', NULL),
  (19345, 567, 'Got to carry you over the threshold.', NULL),
  (19346, 567, 'Who buys them, tax collectors?', NULL),
  (19347, 567, 'Well, I haven''t noticed a big demand for tickets.', NULL),
  (19348, 567, 'I''m sending up a plain, flat, silver one with your initials.', NULL),
  (19349, 567, 'I can''t think of anything more boring or tiresome than what you''ve been through and the last week must be the hardest.', NULL),
  (19350, 567, 'Then I had two fall showings Then I had to have a cocktail with Leland and Slim Hayward.', NULL),
  (19351, 567, 'To think I planted three nice items in the columns about you today.', NULL),
  (19352, 567, 'I wish there was one I wanted.', NULL),
  (19353, 567, 'Guess I''d better start setting up for dinner.', NULL),
  (19354, 567, 'I''d say she''s doing a woman''s hardest job.', NULL),
  (19355, 567, 'It''s almost as if it were being written especially for us.', NULL),
  (19356, 567, 'Well, now look - If you''re saying all this because you don''t want to tell me the truth, because you''re hiding something from me, then maybe I can understand.', NULL),
  (19357, 567, 'It''s ridiculous to say that it can only be done by a special, private little group of anointed people.', NULL),
  (19358, 567, 'Well, you might have to if you went with me.', NULL),
  (19359, 567, 'Well, if there''s one thing I know, it''s how to wear the proper clothes.', NULL),
  (19360, 567, 'Jeff, you don''t have to be deliberately repulsive just to impress me I''m wrong.', NULL),
  (19361, 567, 'No, I don''t particularly want that.', NULL),
  (19362, 567, 'It''s deflating to find out the only way I can be part of it, is to take out a subscription to your magazine.', NULL),
  (19363, 567, 'What''s that supposed to be, ma''am?', NULL),
  (19364, 567, 'Yeah, she''ll wind up fat, alcoholic and miserable.', NULL),
  (19365, 567, 'What would he be selling at three o''clock in the morning?', NULL),
  (19366, 567, 'And don''t sleep in that chair again.', NULL),
  (19367, 567, 'I''m not exactly on the other side of the room.', NULL),
  (19368, 567, 'Why hasn''t he been in his wife''s bedroom all day?', NULL),
  (19369, 567, 'You''re beginning to scare - Shh!', NULL),
  (19370, 567, 'What''s the - What is it you''re looking for?', NULL),
  (19371, 567, 'I''ve seen bickering and family quarrels and mysterious trips at night and knives and saws and rope.', NULL),
  (19372, 567, 'Of course, I - You could see cos the shades were up and he walked along the corridor and the street and the backyard.', NULL),
  (19373, 567, 'Let''s start from the beginning again, Jeff.', NULL),
  (19374, 567, 'Now you go home and get some sleep.', NULL),
  (19375, 567, 'My only thought was throwing a little business your way, that''s all.', NULL),
  (19376, 567, 'No wonder your husband still loves you.', NULL),
  (19377, 567, 'I''ll keep an eye on the alley.', NULL),
  (19378, 567, 'Doyle, don''t tell me he''s an unemployed magician, amusing the neighbourhood with his sleight of hand.', NULL),
  (19379, 567, 'That salesman wouldn''t just knock his wife off after dinner and toss her in the trunk and put her in storage.', NULL),
  (19380, 567, 'Let me poke into it a little on my own.', NULL),
  (19381, 567, 'I think that''s about the time I fell asleep.', NULL),
  (19382, 567, 'Have you checked his bank statements lately?', NULL),
  (19383, 567, 'Now, did anyone, including you, actually see her murdered?', NULL),
  (19384, 567, 'If I were caught in there, they''d have my badge within ten minutes.', NULL),
  (19385, 567, 'Yeah, I can hear myself, "Your Honour, I have a friend who''s an amateur sleuth.', NULL),
  (19386, 567, 'Bloody footsteps leading up to the door?', NULL),
  (19387, 567, 'I guess I''ll go over to the railroad station and check on Thorwald''s story.', NULL),
  (19388, 567, 'You mean you haven''t even heard from him?', NULL),
  (19389, 567, 'Oh, I just - Take a look at Thorwald.', NULL),
  (19390, 567, 'She volunteered plenty, but I never saw him ask her for any.', NULL),
  (19391, 567, 'Women aren''t that unpredictable.', NULL),
  (19392, 567, 'And you don''t leave it behind in your husband''s drawer in your favourite handbag.', NULL),
  (19393, 567, 'I''d like to see your friend''s face when we tell him.', NULL),
  (19394, 567, 'I won''t be able to give you any...', NULL),
  (19395, 567, 'Y-Y-You have a great talent for creating difficult situations.', NULL),
  (19396, 567, 'Why don''t I slip into something more comfortable?', NULL),
  (19397, 567, 'He''s got everything he owns Iaid out over there in the bedroom, waiting to be packed.', NULL),
  (19398, 567, 'You don''t really need any of this information, do you?', NULL),
  (19399, 567, 'Like disposing of their wives?', NULL),
  (19400, 567, 'You can''t ignore the disappearance and the trunk and the jewellery.', NULL),
  (19401, 567, 'I take it you didn''t find the trunk.', NULL),
  (19402, 567, 'Didn''t you take them off to the crime lab?', NULL),
  (19403, 567, 'That''s what''s known as a family problem.', NULL),
  (19404, 567, 'If I''d have been careful piloting that reconnaissance plane you wouldn''t have had the chance to take the pictures that won you a medal, and a good job, and fame, and money.', NULL),
  (19405, 567, 'Oh, Jeff, if you need any more help...', NULL),
  (19406, 567, 'Yeah, he''s kind of young, isn''t he?', NULL),
  (19407, 567, 'Jeff, if someone came in here, they wouldn''t believe what they''d see.', NULL),
  (19408, 567, 'You know, I think I''ll start reviving that tomorrow.', NULL),
  (19409, 567, 'Which one of you killed my dog?', NULL),
  (19410, 567, 'Did you kill him because he liked you?', NULL),
  (19411, 567, 'He''s washing down the bathroom walls.', NULL),
  (19412, 567, 'I hope I took something else besides leg art.', NULL),
  (19413, 567, 'Look, those two yellow zinnias on this end aren''t as tall as they were.', NULL),
  (19414, 567, 'No, my idea is she''s scattered all over town.', NULL),
  (19415, 567, 'Stella, get me some note paper.', NULL),
  (19416, 567, 'Does she have enough of them to - To make her rest easier - Wasn''t that close?', NULL),
  (19417, 567, 'The only way anybody could get that ring would be to chop off my finger.', NULL),
  (19418, 567, 'There''s probably one in the basement.', NULL),
  (19419, 567, 'I''ll see if I can get about 15 minutes.', NULL),
  (19420, 567, 'You wonder if it''s your girlfriend calling, the one you killed for.', NULL),
  (19421, 567, 'One of you keep an eye on this window.', NULL),
  (19422, 567, 'She said ring Thorwald''s phone the second you see him come back.', NULL),
  (19423, 567, 'Get my billfold out of the drawer in the table there.', NULL),
  (19424, 567, 'When those cops see Lisa, they''ll even contribute.', NULL),
  (19425, 567, 'She got into Thorwald''s apartment, but then he came back and the only way I could get her out, was call the police.', NULL),
  (19426, 567, 'All the telephone calls he made were long distance, alright?', NULL),
  (19427, 567, 'If that ring checks out, we''ll give him an escort.', NULL),
  (19428, 567, 'I got here as fast as I could.', NULL),
  (19429, 567, 'Did he say what was buried in the flower bed?', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (23932, 654, 'Now you take it easy, slugger.', NULL),
  (23933, 654, 'I figured the worst they was gonna do was lean on him a little bit.', NULL),
  (23934, 654, 'I''ll be in there later and....', NULL),
  (23935, 654, 'Father, who''d want to kill Joey?', NULL),
  (23936, 654, 'Did you ever hear of a saint hiding in a church?', NULL),
  (23937, 654, 'Where''s that big banker of mine?', NULL),
  (23938, 654, 'Come on, go on, it''s good for you.', NULL),
  (23939, 654, 'Listen, I''m a soft touch, too.', NULL),
  (23940, 654, 'They gave me this to remember them by.', NULL),
  (23941, 654, 'A deal I sweated and bled for, on account of one lousy little cheese-eater...', NULL),
  (23942, 654, 'And Mac, tomorrow morning when you shape the men, put Terry up in the loft.', NULL),
  (23943, 654, 'Come on, Tony, give me the tabs.', NULL),
  (23944, 654, 'Who do you think''ll pay for the funeral?', NULL),
  (23945, 654, 'Mine''s more full of holes than the Pittsburgh infield.', NULL),
  (23946, 654, 'We''ll hold public hearings on waterfront crime...', NULL),
  (23947, 654, 'I don''t know nothing, I ain''t seen nothing, and I''m not saying nothing.', NULL),
  (23948, 654, 'You''re three weeks behind on the last $25, but I''m willing to take a chance.', NULL),
  (23949, 654, 'I see the sisters taught you not to lie.', NULL),
  (23950, 654, 'Dugan, my boy, you''re dreaming again.', NULL),
  (23951, 654, 'Letting her see things ain''t fit for the eyes of a decent girl.', NULL),
  (23952, 654, 'The waterfront is tougher, Father, like it ain''t part of America.', NULL),
  (23953, 654, 'You know what you''re letting yourself in for?', NULL),
  (23954, 654, 'Let me tell you what stooling is.', NULL),
  (23955, 654, 'They''re bad because the mob does the hiring.', NULL),
  (23956, 654, 'All right, then answer this one: How can we call ourselves Christians and protect these murderers with our silence?', NULL),
  (23957, 654, 'They''ll help us get to the bottom of the river.', NULL),
  (23958, 654, 'Are you going to keep still until they cut you down one by one?', NULL),
  (23959, 654, 'It seems to me we''ve gone just about as far as we can at this time.', NULL),
  (23960, 654, 'If I stick my neck out and it''s chopped off, is that the end?', NULL),
  (23961, 654, 'Your brother was a saint, the only one who ever tried to get me compensation.', NULL),
  (23962, 654, 'I guess they don''t let you walk with fellas where you''ve been?', NULL),
  (23963, 654, 'You know, I''ve seen you a lot of times before.', NULL),
  (23964, 654, 'I was just kidding you a little bit.', NULL),
  (23965, 654, 'The way those sisters used to whack me, I don''t know what.', NULL),
  (23966, 654, 'There''s too many guys around here with only one thing on their mind.', NULL),
  (23967, 654, 'Do you know who Terry Malloy is?', NULL),
  (23968, 654, 'He said he wants to see me again.', NULL),
  (23969, 654, 'But I''ve seen things that I know are so wrong.', NULL),
  (23970, 654, 'He thinks I''m a tough man because I boxed pro a lot.', NULL),
  (23971, 654, 'He''s always on top of the perch.', NULL),
  (23972, 654, 'Did you see the fight last night?', NULL),
  (23973, 654, 'Then they stuck Charley and me...', NULL),
  (23974, 654, 'Boy, what a fruitcake you are.', NULL),
  (23975, 654, 'Do it to him before he does it to you.', NULL),
  (23976, 654, 'Everybody''s putting the needle on me.', NULL),
  (23977, 654, 'Down here it''s every man for himself.', NULL),
  (23978, 654, 'Help me if you can for God''s sake.', NULL),
  (23979, 654, 'First I got to kiss the bride.', NULL),
  (23980, 654, 'I think we''re doing pretty good.', NULL),
  (23981, 654, 'Tell him I''ll come over there when I''m ready.', NULL),
  (23982, 654, 'I told you I don''t know nothing about that.', NULL),
  (23983, 654, 'It was Johnny Friendly who had Joey killed, wasn''t it?', NULL),
  (23984, 654, 'You''re driving yourself nuts, you''re driving me nuts.', NULL),
  (23985, 654, 'I''m only trying to help you out.', NULL),
  (23986, 654, 'What you got up there, Chinese bells?', NULL),
  (23987, 654, 'I knew he had the guts, but I never-- Guts!', NULL),
  (23988, 654, 'It''s just the Doyle broad, she''s got him so he doesn''t...', NULL),
  (23989, 654, 'And don''t go walking off with any of that!', NULL),
  (23990, 654, 'Kayo, you''re a walking distillery.', NULL),
  (23991, 654, 'If you don''t think Christ is down here on the waterfront...', NULL),
  (23992, 654, 'You want to know what''s wrong with our waterfront?', NULL),
  (23993, 654, 'He''s kneeling right here beside Dugan and He''s saying with all of you: "If you do it to the least of mine, you do it to me.', NULL),
  (23994, 654, 'Kayo Dugan and keeping your mouth shut when you know the score.', NULL),
  (23995, 654, 'There''s nothing I haven''t heard.', NULL),
  (23996, 654, 'She''s the first nice thing that''s ever happened to me.', NULL),
  (23997, 654, 'They''re asking me to put the finger on my own brother.', NULL),
  (23998, 654, 'That stuff can drive you nuts.', NULL),
  (23999, 654, 'Suppose I knew a guy that knocked somebody off...', NULL),
  (24000, 654, 'Didn''t I see you in the Garden three or four years ago...', NULL),
  (24001, 654, 'Why didn''t you finish him off?', NULL),
  (24002, 654, 'Was that a hook or an uppercut you caught him with that first time?', NULL),
  (24003, 654, 'So they''ve been seen together and he smiled at her.', NULL),
  (24004, 654, 'After all the days I gave him in the loft, he''s got no gratitude.', NULL),
  (24005, 654, 'Maybe the boy is out of line, but he''s just a confused kid!', NULL),
  (24006, 654, 'I thought we was going to the Garden?', NULL),
  (24007, 654, 'The guys know you''re not a cheese-eater.', NULL),
  (24008, 654, 'There''s a boss loader slot that''s open on the new pier we''re opening up.', NULL),
  (24009, 654, 'You''re not thinking of testifying against some people that we might know?', NULL),
  (24010, 654, 'I''m telling you, I haven''t made up my mind yet!', NULL),
  (24011, 654, 'That skunk we got you for a manager...', NULL),
  (24012, 654, 'A one-way ticket to Palookaville!', NULL),
  (24013, 654, 'Ten to one they won''t believe me.', NULL),
  (24014, 654, 'Shut up about that conscience, that''s all I''ve been hearing!', NULL),
  (24015, 654, 'Let''s get out of here, please.', NULL),
  (24016, 654, 'Why don''t you go home before Big John gets here?', NULL),
  (24017, 654, 'Do you really want to finish him?', NULL),
  (24018, 654, 'Unless you haven''t the guts, and if you haven''t, hold onto it!', NULL),
  (24019, 654, 'Before you call the next witness...', NULL),
  (24020, 654, 'Friendly, or I should say, Mr.', NULL),
  (24021, 654, 'You don''t drive a truck or a cab...', NULL),
  (24022, 654, 'Are you sure they''re your friends?', NULL),
  (24023, 654, 'Are they taking chances for you?', NULL),
  (24024, 654, 'I''m just going to go down there...', NULL),
  (24025, 654, 'You''re still short in the hatch, Mac.', NULL),
  (24026, 654, 'They''ll be down on us for the slightest infraction now, anything.', NULL),
  (24027, 654, 'At the right time I''ll catch up with you.', NULL),
  (24028, 654, 'But I''m standing over here now!', NULL),
  (24029, 654, 'Yours truly is in charge here.', NULL),
  (24030, 654, 'All my life you pushed me around.', NULL),
  (24031, 654, 'Then it''ll give us back our union, so we can run it on the up and up.', NULL),
  (24232, 665, 'You''ll be counted at Bethlehem.', NULL),
  (24233, 665, 'He said to me: "I must be about my father''s business.', NULL),
  (24234, 665, 'If you want to rise, Sextus, do the difficult.', NULL),
  (24235, 665, 'I tell you, they''re drunk with religion.', NULL),
  (24236, 665, 'There was one predicted when I was a boy.', NULL),
  (24237, 665, 'You''ve been too long away from Rome.', NULL),
  (24238, 665, 'When I heard that news, I drank a toast to you.', NULL),
  (24239, 665, 'Or have you become too dignified?', NULL),
  (24240, 665, 'I''m going to be second-in-command to the new governor, Valerius Gratus.', NULL),
  (24241, 665, 'I''m next in authority to the governor, and you''re my friend.', NULL),
  (24242, 665, 'It''s no accident that one small village on the Tiber.', NULL),
  (24243, 665, 'Your family''s name is honored.', NULL),
  (24244, 665, 'It is worse than stupid, futile!', NULL),
  (24245, 665, 'It''s especially fermented for the Roman army.', NULL),
  (24246, 665, 'The court where we played at changing the guard.', NULL),
  (24247, 665, 'He was a boy when he left us, now he''s a man.', NULL),
  (24248, 665, 'I chose the right present for you.', NULL),
  (24249, 665, 'Most of the men agree with me.', NULL),
  (24250, 665, 'This is my great opportunity, and yours too.', NULL),
  (24251, 665, 'The emperor is watching us, judging us.', NULL),
  (24252, 665, 'Besides, you must understand this, Messala.', NULL),
  (24253, 665, 'Rome is strangling my people and my country, the whole earth!', NULL),
  (24254, 665, 'Blessed art Thou, O Lord, our God, King of the world.', NULL),
  (24255, 665, 'I also bring good news from Antioch.', NULL),
  (24256, 665, 'My life belongs to the House of Hur.', NULL),
  (24257, 665, 'Still, Esther has come with me from Antioch for your permission to marry.', NULL),
  (24258, 665, 'You''re eager to marry, Esther?', NULL),
  (24259, 665, 'We''ll drink to your happiness.', NULL),
  (24260, 665, 'I touched your face as you lay there.', NULL),
  (24261, 665, 'The gods favor my lord Gratus.', NULL),
  (24262, 665, 'Open up in the name of the law!', NULL),
  (24263, 665, 'In the name of God, tell them it''s a mistake.', NULL),
  (24264, 665, 'There''s no truth in the charge!', NULL),
  (24265, 665, 'I didn''t try to kill the governor.', NULL),
  (24266, 665, 'Kill me, and your mother and sister will die.', NULL),
  (24267, 665, 'Then there must be no doubt in your mind, the charge is groundless.', NULL),
  (24268, 665, 'All right, on your feet, all of you!', NULL),
  (24269, 665, 'Your eyes are full of hate, 41 .', NULL),
  (24270, 665, 'The emperor has honored us with the task.', NULL),
  (24271, 665, 'He has no more power than the images I pray to.', NULL),
  (24272, 665, 'Two people were condemned with me, my mother and sister.', NULL),
  (24273, 665, 'If we are not, you will sink with this ship, chained to your oar.', NULL),
  (24274, 665, 'Better for us both if it''s the enemy.', NULL),
  (24275, 665, 'The man who saved me, divine emperor, to return and serve you.', NULL),
  (24276, 665, 'His attack upon our governor is one upon the senate and the people of Rome.', NULL),
  (24277, 665, 'You all know him as the finest charioteer in Rome.', NULL),
  (24278, 665, 'Nothing could make stronger our bond.', NULL),
  (24279, 665, 'My old friend Pontius Pilate, young Arrius.', NULL),
  (24280, 665, 'But it seems the wilderness needs my particular talents.', NULL),
  (24281, 665, 'But still, my counsel is to wait.', NULL),
  (24282, 665, 'Here is a part of my life which you have made for me.', NULL),
  (24283, 665, 'Give me those reins, you fool!', NULL),
  (24284, 665, 'Tell me, my friend, could you make my four run as one?', NULL),
  (24285, 665, 'And let me hear how you raced in Rome.', NULL),
  (24286, 665, 'You''re a Jew, yet you drove in the great circus.', NULL),
  (24287, 665, 'Ah, well, then perhaps you will come back.', NULL),
  (24288, 665, 'Was the food not to your liking?', NULL),
  (24289, 665, 'You are the slowest, and you can run all day without tiring.', NULL),
  (24290, 665, 'You are the swiftest, but you must be steady.', NULL),
  (24291, 665, 'At Jerusalem, they''ll race the world''s finest teams.', NULL),
  (24292, 665, 'Just think, his defeat and humiliation at the hands of a Jew!', NULL),
  (24293, 665, 'I see this terrible thing in your eyes.', NULL),
  (24294, 665, 'Yet God once spoke to me out of the darkness.', NULL),
  (24295, 665, 'There are many paths to God, my son.', NULL),
  (24296, 665, 'You never went back to Antioch?', NULL),
  (24297, 665, 'There is Malluch, my other half.', NULL),
  (24298, 665, 'Since then, I have been his tongue.', NULL),
  (24299, 665, 'I see that your one thought is to save your mother and sister.', NULL),
  (24300, 665, 'Who lives more than one year in the galleys?', NULL),
  (24301, 665, 'I was saying: "If you were not a bride, I should kiss you goodbye.', NULL),
  (24302, 665, 'If he says they''re dead-- Messala will wish they were living.', NULL),
  (24303, 665, 'Only if I can give up thinking and feeling.', NULL),
  (24304, 665, 'He''s a champion of the great circus.', NULL),
  (24305, 665, 'By what magic do you bear the name of a consul of Rome?', NULL),
  (24306, 665, 'Your gift is exquisitely appropriate, young Arrius.', NULL),
  (24307, 665, 'Restore them to me, and I''ll forget what I vowed.', NULL),
  (24308, 665, 'And I''ve been here three years.', NULL),
  (24309, 665, 'I pray to God they''re alive and that Messala will free them.', NULL),
  (24310, 665, 'You do us an unexpected honor.', NULL),
  (24311, 665, 'Your spirit does you credit, but do not be impatient.', NULL),
  (24312, 665, 'Perhaps I made a mistake in coming here.', NULL),
  (24313, 665, 'They have taken me into their family.', NULL),
  (24314, 665, 'You will make him see what men are born in this land.', NULL),
  (24315, 665, 'To shine out for your people and my people together.', NULL),
  (24316, 665, 'Let us honor those who race for us today.', NULL),
  (24317, 665, 'If you wish us to keep you alive, we have to go to work now, tribune.', NULL),
  (24318, 665, 'You think they''re dead, your mother and sister.', NULL),
  (24319, 665, 'Let them be as if you had never come here.', NULL),
  (24320, 665, 'How could you have suffered them to come here?', NULL),
  (24321, 665, 'I should have done better if I had poured it into the sand.', NULL),
  (24322, 665, 'I have just come from the Valley of Stone.', NULL),
  (24323, 665, 'Rome has said she is ready to join your life to hers in a great future.', NULL),
  (24324, 665, 'I cross this floor in spoken friendship.', NULL),
  (24325, 665, 'If you stay here, you will find yourself part of this tragedy.', NULL),
  (24326, 665, 'I was afraid you would never come back.', NULL),
  (24327, 665, 'In that dead valley where we left them?', NULL),
  (24328, 665, 'Do good to those who despitefully use you.', NULL),
  (24329, 665, 'Hatred is turning you to stone.', NULL),
  (24330, 665, 'I cannot bear that you should have never known.', NULL),
  (24331, 665, 'This is where your search has brought you, Balthasar.', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (26132, 705, 'The Sarah Siddons Award is perhaps unknown to you.', NULL),
  (26133, 705, 'I am essential to the theatre.', NULL),
  (26134, 705, 'She''s been profiled, covered, revealed, reported, what she eats and what she wears and whom she knows and where she was and when and where she''s going.', NULL),
  (26135, 705, 'I''m the lowest form of celebrity.', NULL),
  (26136, 705, 'You can breathe it, can''t you?', NULL),
  (26137, 705, 'I can''t see that Lloyd''s plays have hurt you any.', NULL),
  (26138, 705, 'I thought you''d forgotten about me.', NULL),
  (26139, 705, 'I''d like anything Miss Channing played in.', NULL),
  (26140, 705, 'But you must have friends, a home, family?', NULL),
  (26141, 705, 'What they were isn''t important.', NULL),
  (26142, 705, 'We played Liliom for three performances.', NULL),
  (26143, 705, 'I found a job, and his insurance helped.', NULL),
  (26144, 705, 'Show me a human and I might have.', NULL),
  (26145, 705, 'I''ll be at the old stand tomorrow matinee.', NULL),
  (26146, 705, 'What rules say the theatre exists only within some ugly buildings crowded into one square mile of New York City?', NULL),
  (26147, 705, 'I read George Jean Nathan every week.', NULL),
  (26148, 705, 'I mean, you haven''t had a minute alone yet.', NULL),
  (26149, 705, 'You''re conceited, thoughtless and messy.', NULL),
  (26150, 705, 'From now on it isn''t applause, just something to do till the aisles get cleared.', NULL),
  (26151, 705, 'We now got everything a dressing room needs except a basketball hoop.', NULL),
  (26152, 705, 'Yes, it is, but I don''t understand.', NULL),
  (26153, 705, 'She hasn''t missed a week since I left.', NULL),
  (26154, 705, 'Well, what do you think of my elegant new suit?', NULL),
  (26155, 705, 'Last night I meant to tell you before you went out.', NULL),
  (26156, 705, 'There was nothing he didn''t know.', NULL),
  (26157, 705, 'I looked through the wrong end of the camera.', NULL),
  (26158, 705, 'She''s a girl of so many interests.', NULL),
  (26159, 705, 'She''s a young lady of qualities.', NULL),
  (26160, 705, 'I haven''t let those become too important.', NULL),
  (26161, 705, 'Do I get dragged off to the snake pits?', NULL),
  (26162, 705, 'What has or is about to happen?', NULL),
  (26163, 705, 'Until now, we''ve only met in passing.', NULL),
  (26164, 705, 'Now, don''t worry about your little charge.', NULL),
  (26165, 705, 'Margo, you by any chance haven''t got any bicarbonate of soda in the house?', NULL),
  (26166, 705, 'And now you can do me a great favor.', NULL),
  (26167, 705, 'Max, Karen''s decided it''s time to go.', NULL),
  (26168, 705, 'Three months ago I was 40 years old.', NULL),
  (26169, 705, 'It has everything to do with you having a fight with Bill.', NULL),
  (26170, 705, 'Not that I''d consider anything that would take me away from her.', NULL),
  (26171, 705, 'You think Miss Channing would approve?', NULL),
  (26172, 705, 'I admit there''s a screwball element in the theatre.', NULL),
  (26173, 705, 'Like waves of love coming over the footlights and wrapping you up.', NULL),
  (26174, 705, 'You''re maudlin and full of self-pity.', NULL),
  (26175, 705, 'Take my clothes off, hold my head?', NULL),
  (26176, 705, 'Well, if she has to pick on someone, I''d just as soon it was me.', NULL),
  (26177, 705, 'Margo, I have lived in the theatre as a Trappist monk lives in his faith.', NULL),
  (26178, 705, 'Neither your name nor your performance entered the conversation.', NULL),
  (26179, 705, 'How did you get the idea of letting Eve read with Miss Casswell?', NULL),
  (26180, 705, 'It must have seemed so new and fresh to you, so exciting, to have your lines read just as you wrote them.', NULL),
  (26181, 705, 'That would solve none of their problems because actresses never die!', NULL),
  (26182, 705, 'And you, I take it, are the Paderewski who plays his concerto on me, the piano?', NULL),
  (26183, 705, 'The playwright doesn''t make the performance.', NULL),
  (26184, 705, 'But due to some uncontrollable drive, you permit the slightest action of a kid...', NULL),
  (26185, 705, 'But you won''t or can''t tell me.', NULL),
  (26186, 705, 'Margo hasn''t done badly by it.', NULL),
  (26187, 705, 'The answer was buzzing around me like a fly.', NULL),
  (26188, 705, 'We''ll be at the station in plenty of time.', NULL),
  (26189, 705, 'You know I don''t pay attention to those things.', NULL),
  (26190, 705, 'I wish someone would tell me about me.', NULL),
  (26191, 705, 'Margo, Bill is all of eight years younger than you.', NULL),
  (26192, 705, 'To so many things I want to be for Bill.', NULL),
  (26193, 705, 'You''re something with a French provincial office or a...', NULL),
  (26194, 705, 'You shouldn''t have had any doubts.', NULL),
  (26195, 705, 'I''m only human, rumors to the contrary, and I''m as curious as the next man.', NULL),
  (26196, 705, 'But if I may make a suggestion...', NULL),
  (26197, 705, 'After you change, if you''re not busy elsewhere, we could have supper.', NULL),
  (26198, 705, 'Tell me, do you share my high opinion of San Francisco?', NULL),
  (26199, 705, 'I''ve heard the most wonderful things about your performance.', NULL),
  (26200, 705, 'Why not read my column to pass the time?', NULL),
  (26201, 705, 'I came as soon as I read that piece of filth.', NULL),
  (26202, 705, 'What with taxes coming up, and, since I''m a playwright and not an oil-well operator, I was thinking...', NULL),
  (26203, 705, 'Lloyd Richards, do not consider giving that contemptible little worm the part of Cora!', NULL),
  (26204, 705, 'I said she''d be fine for the part but there were practical difficulties.', NULL),
  (26205, 705, 'Tomorrow we meet at City Hall at ten.', NULL),
  (26206, 705, 'May we never be farther apart.', NULL),
  (26207, 705, 'I am busting to find out what''s going on in that feverish little brain waiting in there.', NULL),
  (26208, 705, 'Smart, good head on my shoulders, that sort of thing.', NULL),
  (26209, 705, 'Do you expect me to believe that you didn''t say any of that?', NULL),
  (26210, 705, 'You have a powerful friend in Addison.', NULL),
  (26211, 705, 'Don''t you know that part was written for Margo?', NULL),
  (26212, 705, 'You and Lloyd, how long, even in the theatre, before people forgot what happened and trusted you again?', NULL),
  (26213, 705, 'Oddly enough, she didn''t say a word about Margo.', NULL),
  (26214, 705, 'Never have I seen so much elite, all with their eyes on me, waiting for me to crack that little gnome on the noggin with a bottle.', NULL),
  (26215, 705, 'Well, I don''t want to play Cora.', NULL),
  (26216, 705, 'Lloyd never got around to asking whether it was all right with me for Eve to play Cora.', NULL),
  (26217, 705, 'She''s been crying all night and she''s hysterical.', NULL),
  (26218, 705, 'It''ll bring me everything I''ve ever wanted.', NULL),
  (26219, 705, 'We''re having everyone up after the performance.', NULL),
  (26220, 705, 'He''ll write great plays for me.', NULL),
  (26221, 705, 'We sat and talked until it was light.', NULL),
  (26222, 705, 'Yes, you did, and you still do.', NULL),
  (26223, 705, 'What have you got to do with it?', NULL),
  (26224, 705, 'When that alarm goes off, go to your battle stations.', NULL),
  (26225, 705, 'That $500 brought you straight to New York.', NULL),
  (26226, 705, 'You used my name to blackmail Karen into getting you the part of Cora.', NULL),
  (26227, 705, 'For me to thank you as equals would be presumptuous.', NULL),
  (26228, 705, 'How can I repay Lloyd Richards?', NULL),
  (26229, 705, 'I don''t suppose there''s a drink left?', NULL),
  (26230, 705, 'I was afraid someone would notice the lights were on, so I turned them off.', NULL),
  (26231, 705, 'How''d you get up here from Brooklyn?', NULL),
  (29829, 804, 'I''m so glad that you could come.', NULL),
  (29830, 804, 'My dear, you have lovely things.', NULL),
  (29831, 804, 'Please put on your slippers and come away from the window.', NULL),
  (29832, 804, 'Now, my dear, if you don''t mind, tomorrow''s schedule.', NULL),
  (29833, 804, 'I don''t care if it spilled or not.', NULL),
  (29834, 804, 'I''ll only disturb Your Royal Highness for a moment.', NULL),
  (29835, 804, 'I''ll bow and I''ll smile and...', NULL),
  (29836, 804, 'Best thing I know is to do exactly what you wish for a while.', NULL),
  (29837, 804, 'One more round and I''m gonna throw you gents right out in the snow.', NULL),
  (29838, 804, 'Couldn''t be anything to do with the fact that you''re ahead?', NULL),
  (29839, 804, 'You know, people who can''t handle liquor shouldn''t drink it.', NULL),
  (29840, 804, 'Yeah, I couldn''t agree with you more, but...', NULL),
  (29841, 804, 'Look, "signore", for me it is very late night.', NULL),
  (29842, 804, 'I''m terribly sorry to mention it, but...', NULL),
  (29843, 804, 'I''m afraid you''ll have to rough it tonight...', NULL),
  (29844, 804, 'Will you help me get undressed, please?', NULL),
  (29845, 804, 'I think I''ll go out for a cup of coffee.', NULL),
  (29846, 804, 'Have you searched the grounds?', NULL),
  (29847, 804, 'I must remind you that the princess is the direct heir to the throne.', NULL),
  (29848, 804, 'We start our days at 8:30 in this office.', NULL),
  (29849, 804, 'How did Her Highness react to the idea of a European federation?', NULL),
  (29850, 804, 'They''ve got a lot more on the ball than we suspect.', NULL),
  (29851, 804, 'Oh, you mean what did she have on?', NULL),
  (29852, 804, 'I think I know the dress you mean.', NULL),
  (29853, 804, 'I think you described it very well...', NULL),
  (29854, 804, 'All right, all right, I overslept.', NULL),
  (29855, 804, 'It isn''t Annie Oakley, Dorothy Lamour or Madame Chiang Kai-shek.', NULL),
  (29856, 804, 'When I want to fire you, you won''t have to ask.', NULL),
  (29857, 804, 'How much would a real interview with this dame be worth?', NULL),
  (29858, 804, 'I''m talking about her views on everything.', NULL),
  (29859, 804, 'I plan to enter her sick room disguised as a thermometer.', NULL),
  (29860, 804, 'Five hundred says you don''t come up with the story.', NULL),
  (29861, 804, 'When you lose this bet, you''ll owe me a thousand.', NULL),
  (29862, 804, 'I''m gonna win that money, and I''m gonna buy a one-way ticket back to New York.', NULL),
  (29863, 804, 'How would you like to make some money?', NULL),
  (29864, 804, 'Now, if you''ll just lend me a little cash...', NULL),
  (29865, 804, 'I dreamt I was asleep in the street...', NULL),
  (29866, 804, 'Would you be so kind as to tell me...', NULL),
  (29867, 804, 'So I''ve spent the night here...', NULL),
  (29868, 804, 'You don''t know how delighted I am to meet you.', NULL),
  (29869, 804, 'You''re not what I would call trouble.', NULL),
  (29870, 804, 'Can you get here in five minutes?', NULL),
  (29871, 804, 'Joe, I''m up to my ears in work.', NULL),
  (29872, 804, 'I''m busy now, and I''m meeting Francesca at Rocca''s in half an hour.', NULL),
  (29873, 804, 'I only waited to say good-bye.', NULL),
  (29874, 804, 'Thank you for letting me sleep in your bed.', NULL),
  (29875, 804, 'How much was it that you wanted?', NULL),
  (29876, 804, 'Tell me how I double my money that way?', NULL),
  (29877, 804, 'You don''t mind if I just borrow it, do you?', NULL),
  (29878, 804, 'It''s on a boat on the "Tevere"...', NULL),
  (29879, 804, 'If you come, you will be most pretty of all girl.', NULL),
  (29880, 804, 'Oh, what was the matter, trouble with the teacher?', NULL),
  (29881, 804, 'They gave me something last night to make me sleep.', NULL),
  (29882, 804, 'I could do some of the things I''ve always wanted to.', NULL),
  (29883, 804, 'I''d like to sit at a sidewalk cafe and look in shop windows...', NULL),
  (29884, 804, 'You don''t want to do a lot of silly things.', NULL),
  (29885, 804, 'What would they say if they knew I''d spent the night in your room?', NULL),
  (29886, 804, 'Must be quite a life you have in that school.', NULL),
  (29887, 804, 'I''ve heard him complain about it.', NULL),
  (29888, 804, 'You know, that''s what everybody says.', NULL),
  (29889, 804, 'Hey, anybody ever tell you you''re a dead ringer for...', NULL),
  (29890, 804, 'Bradley''s just been telling me all about his work.', NULL),
  (29891, 804, 'You''re twisting my arm, you know.', NULL),
  (29892, 804, 'If it wasn''t for that hair, I''d swear that...', NULL),
  (29893, 804, 'Look, Irving, this is my story.', NULL),
  (29894, 804, 'You gonna buy the crown jewels?', NULL),
  (29895, 804, 'We can''t go running around town with a hot princess.', NULL),
  (29896, 804, 'You won''t believe this, but it''s my very first.', NULL),
  (29897, 804, 'I''ll pick this one up, Irving.', NULL),
  (29898, 804, 'Well, you say you''re with the press, you can get away with anything.', NULL),
  (29899, 804, 'I''m a good liar, too, aren''t I?', NULL),
  (29900, 804, 'What do they mean, all these inscriptions?', NULL),
  (29901, 804, 'Then at midnight, I''ll turn into a pumpkin...', NULL),
  (29902, 804, 'That big business development of yours that you have to attend to.', NULL),
  (29903, 804, 'You''ve spent the whole day doing things I''ve always wanted to.', NULL),
  (29904, 804, 'He cut my hair this afternoon.', NULL),
  (29905, 804, 'You''ll dance quietly towards the entrance.', NULL),
  (29906, 804, 'I guess we better get Irving''s car and get out of here.', NULL),
  (29907, 804, 'Well, life isn''t always what one likes, is it?', NULL),
  (29908, 804, 'I can sew, too, and clean a house and iron.', NULL),
  (29909, 804, 'I just haven''t had the chance...', NULL),
  (29910, 804, 'You must stay in the car and drive away.', NULL),
  (29911, 804, 'I don''t know how to say good-bye.', NULL),
  (29912, 804, 'Ma''am, you must appreciate that I have my duty to perform...', NULL),
  (29913, 804, 'I would not have come back tonight...', NULL),
  (29914, 804, 'First, you come into my office and ask about an exclusive on the princess.', NULL),
  (29915, 804, 'What kind of newspaperman are you?', NULL),
  (29916, 804, 'You got here at the right time.', NULL),
  (29917, 804, 'Hey, did you tell him about Smitty?', NULL),
  (29918, 804, 'Hey, what kind of a routine is that?', NULL),
  (29919, 804, 'Yesterday I thought I had a good lead, but I was wrong.', NULL),
  (29920, 804, 'Irving, I don''t know just how to tell you this, but...', NULL),
  (29921, 804, 'You want to have a look at ''em?', NULL),
  (29922, 804, 'You want to know the caption I had in mind there?', NULL),
  (29923, 804, 'It''s always open season on princesses.', NULL),
  (29924, 804, 'You''ll get a good price for ''em.', NULL),
  (29925, 804, 'Does Your Highness believe that federation...', NULL),
  (29926, 804, 'May I say, speaking for my own press service...', NULL),
  (29927, 804, 'Which of the cities visited did Your Highness enjoy the most?', NULL),
  (29928, 804, 'Thank you, ladies and gentlemen.', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (30929, 826, 'If the new prisoners see us digging graves, they may run.', NULL),
  (30930, 826, 'I want you to keep this lighter.', NULL),
  (30931, 826, 'Before that happens we''ll be far away from here, chum.', NULL),
  (30932, 826, 'You''re neither an officer nor a gentleman.', NULL),
  (30933, 826, 'We are an island in the jungle.', NULL),
  (30934, 826, 'My officers and I will be responsible for their conduct.', NULL),
  (30935, 826, 'We found him and an Australian.', NULL),
  (30936, 826, 'We''ll find some decent clothing.', NULL),
  (30937, 826, 'I must say he seems quite a reasonable type.', NULL),
  (30938, 826, 'Yes, yes, I''m sure Jennings has a plan, but escape?', NULL),
  (30939, 826, 'But my men and I are involved in a curious legal point...', NULL),
  (30940, 826, 'Then we have the opportunity to introduce it.', NULL),
  (30941, 826, 'So long as they have that idea, they''ll be soldiers and not slaves.', NULL),
  (30942, 826, 'Notice I do not say English soldiers.', NULL),
  (30943, 826, 'Your shame is their dishonour.', NULL),
  (30944, 826, 'I must call your attention, Colonel Saito...', NULL),
  (30945, 826, 'My officers will not do manual labour.', NULL),
  (30946, 826, 'Colonel Saito, I''ve seen and heard everything.', NULL),
  (30947, 826, 'The kind of guts that can get us all killed.', NULL),
  (30948, 826, 'For he''s a jolly good fellow For he''s a jolly good fellow...', NULL),
  (30949, 826, 'Those prisoners who tried to escape, they were in your charge.', NULL),
  (30950, 826, 'The men don''t work well without their own officers.', NULL),
  (30951, 826, 'I''ll be forced to close the hospital...', NULL),
  (30952, 826, 'I''ve got something to tell you.', NULL),
  (30953, 826, 'Wouldn''t the officers be better off working than suffocating in that hole?', NULL),
  (30954, 826, 'No one will ever know or care what happens to us.', NULL),
  (30955, 826, 'Three men killed, and to what end?', NULL),
  (30956, 826, 'As medical officer, I protest the way he''s being treated.', NULL),
  (30957, 826, 'Therefore, I have removed him from his post.', NULL),
  (30958, 826, 'He''s given us our- Hey, he''s given us our own Red Cross parcels.', NULL),
  (30959, 826, 'I studied at the London Polytechnic.', NULL),
  (30960, 826, 'I do not think you quite realize my position.', NULL),
  (30961, 826, 'My orders were only intended for officers below- No officers will do manual labour.', NULL),
  (30962, 826, 'I''m sure we can arrive at a solution.', NULL),
  (30963, 826, 'If it''s gone, he ceases to command.', NULL),
  (30964, 826, 'You are stubborn but have no pride.', NULL),
  (30965, 826, 'I have given your troops a day of rest.', NULL),
  (30966, 826, 'We must put a stop to these demonstrations.', NULL),
  (30967, 826, 'Hughes, if this were your bridge, how would you use the men?', NULL),
  (30968, 826, 'Fortunately, we have the means at hand.', NULL),
  (30969, 826, 'You''ve got to keep them occupied.', NULL),
  (30970, 826, 'Tell me what you want and we''ll get it.', NULL),
  (30971, 826, 'Colonel, could we have a cup of tea?', NULL),
  (30972, 826, 'I''m sure it will meet with your approval.', NULL),
  (30973, 826, 'Would it be possible to have dinner?', NULL),
  (30974, 826, 'I have already given the order.', NULL),
  (30975, 826, 'Thank you, Colonel Saito, for your kind attention.', NULL),
  (30976, 826, 'Don''t forget we wasted a month through an unfortunate disagreement...', NULL),
  (30977, 826, 'You give me powders, pills, baths, injections, enemas...', NULL),
  (30978, 826, 'Where there''s a hospital, there''s alcohol.', NULL),
  (30979, 826, 'We have an interest in that railway you worked on.', NULL),
  (30980, 826, 'If you want to go over the whole thing again.', NULL),
  (30981, 826, 'You see, he''s gained the initiative.', NULL),
  (30982, 826, 'He believes in keeping our training as close to real life as possible.', NULL),
  (30983, 826, 'It''s twice as powerful as gelignite at half the weight.', NULL),
  (30984, 826, 'I taught Oriental languages at Cambridge before the war.', NULL),
  (30985, 826, 'They were about to shoot him and he didn''t bat an eye.', NULL),
  (30986, 826, 'It''s too far for bombers to carry a load.', NULL),
  (30987, 826, 'You see, none of us have ever been there.', NULL),
  (30988, 826, 'How would you feel about going back?', NULL),
  (30989, 826, 'I belong to the American Navy.', NULL),
  (30990, 826, 'When the Houston sunk, I made it ashore with a real commander.', NULL),
  (30991, 826, 'I kind of got used to being a commander...', NULL),
  (30992, 826, 'Once that happens, I''ve got it made.', NULL),
  (30993, 826, 'If my Navy finds out who I am...', NULL),
  (30994, 826, 'At the same time, they can''t bring you home...', NULL),
  (30995, 826, 'He volunteered to go and help me blow up the bridge.', NULL),
  (30996, 826, 'Are you convinced that building this bridge is a good idea?', NULL),
  (30997, 826, 'The fact is, what we''re doing could be construed as...', NULL),
  (30998, 826, 'Or have it said we can''t do a proper job?', NULL),
  (30999, 826, 'You were in need of medical attention?', NULL),
  (31000, 826, 'The opinion I want is Shears''.', NULL),
  (31001, 826, 'Well, sir, I just checked columns and columns of figures...', NULL),
  (31002, 826, 'They don''t expect you to think.', NULL),
  (31003, 826, 'I''ve tried to imagine myself...', NULL),
  (31004, 826, 'I had an air reconnaissance report on the village.', NULL),
  (31005, 826, 'Well, feel like a sniff of air?', NULL),
  (31006, 826, 'You''re telling me not to be taken alive.', NULL),
  (31007, 826, 'It''s one thing to play with explosives like a kid with firecrackers- He''s not without experience, you know.', NULL),
  (31008, 826, 'He says it''s dangerous to spend the night here.', NULL),
  (31009, 826, 'She''s telling you to hold still.', NULL),
  (31010, 826, 'If we stay, we''ll be up to our necks.', NULL),
  (31011, 826, 'If you hadn''t fixed the radio, we wouldn''t know about the train.', NULL),
  (31012, 826, 'I''ve asked the officers to help, but that won''t do it.', NULL),
  (31013, 826, 'There''s not a man in this hospital who doesn''t belong there.', NULL),
  (31014, 826, 'I wonder if fresh air and light duties might do more than being cooped up.', NULL),
  (31015, 826, 'For those of you who feel up to it...', NULL),
  (31016, 826, 'I didn''t give orders for a halt.', NULL),
  (31017, 826, 'You''ve got to get there before sundown.', NULL),
  (31018, 826, 'You carry the stench of death like the plague.', NULL),
  (31019, 826, 'You''re in command again, you know.', NULL),
  (31020, 826, 'Since we don''t know what time it''ll cross tomorrow...', NULL),
  (31021, 826, 'Sir, I was the best swimmer in my course.', NULL),
  (31022, 826, 'I''ll set up the mortar here to create an additional diversion.', NULL),
  (31023, 826, 'You know, if it wasn''t for my ankle, I''d take Joyce''s assignment.', NULL),
  (31024, 826, 'I haven''t been at home more than ten months in all that time.', NULL),
  (31025, 826, 'Most of you move on tomorrow to a new camp and new construction.', NULL),
  (31026, 826, 'I suppose many of you feel somewhat let down.', NULL),
  (31027, 826, 'I can''t think of what it could be.', NULL),
  (31028, 826, 'As you once said, sir, I''ve got a lot to learn about the army.', NULL),
  (31777, 845, 'I saw you blast Faraday right off the court in South Orange last season.', NULL),
  (31778, 845, 'You know, it must be pretty exciting to be so important.', NULL),
  (31779, 845, 'I''ll bet I can guess who "A" is.', NULL),
  (31780, 845, 'Even about people I don''t know.', NULL),
  (31781, 845, 'Oh, I''ve got a wonderful theory about that.', NULL),
  (31782, 845, 'Who would want to stop off at Metcalf?', NULL),
  (31783, 845, 'Are there any seats in the diner?', NULL),
  (31784, 845, 'What do you think of a man like that?', NULL),
  (31785, 845, 'Have you ever driven a car blindfolded at 150 miles an hour?', NULL),
  (31786, 845, 'Can''t I look beyond a tennis net without being out for something?', NULL),
  (31787, 845, 'Want to hear one of my ideas for a perfect murder?', NULL),
  (31788, 845, 'One of those useless men Miriam played around with?', NULL),
  (31789, 845, 'I used to put myself to sleep at night, figuring it out.', NULL),
  (31790, 845, 'Each one has somebody that he''d like to get rid of.', NULL),
  (31791, 845, 'We talk the same language, don''t we?', NULL),
  (31792, 845, 'Park these in a lucky spot, will you?', NULL),
  (31793, 845, 'I sort of hoped it was because you were jealous.', NULL),
  (31794, 845, 'Especially when you''re going to have another man''s baby.', NULL),
  (31795, 845, 'What are you trying to say, Miriam?', NULL),
  (31796, 845, 'Now I can buy me some pretty new clothes.', NULL),
  (31797, 845, 'It''s serious between you two, huh?', NULL),
  (31798, 845, 'Especially when he''s to be a father.', NULL),
  (31799, 845, 'That''s what should happen to people like you.', NULL),
  (31800, 845, 'I''m coming to Washington to have my baby!', NULL),
  (31801, 845, 'I do wish you''d keep your hands quiet.', NULL),
  (31802, 845, 'Now, you haven''t been doing anything foolish?', NULL),
  (31803, 845, 'Get shaved before your father gets home.', NULL),
  (31804, 845, 'I was trying to paint Saint Francis.', NULL),
  (31805, 845, 'He needs to go someplace for treatment before it''s too late!', NULL),
  (31806, 845, 'If necessary, under restraint!', NULL),
  (31807, 845, 'I never saw a girl eat so much.', NULL),
  (31808, 845, 'Step right up and get your ticket cashed!', NULL),
  (31809, 845, 'You''ll never make the Metropolitan.', NULL),
  (31810, 845, 'There''s nothing for us to worry about.', NULL),
  (31811, 845, 'We''d both be arrested for murder.', NULL),
  (31812, 845, 'Unless it was part of the plan, and you were in on it.', NULL),
  (31813, 845, 'Someone has some news for you, Guy.', NULL),
  (31814, 845, 'Go, before I give you what you gave Miriam.', NULL),
  (31815, 845, 'Anne, darling, you''re trembling.', NULL),
  (31816, 845, 'The police have been trying to find you.', NULL),
  (31817, 845, 'We can''t overlook that murder is at our doorstep...', NULL),
  (31818, 845, 'You can tell them where you were.', NULL),
  (31819, 845, 'Daddy doesn''t mind a little scandal.', NULL),
  (31820, 845, 'Father, it''s getting terribly late.', NULL),
  (31821, 845, 'It''d be wonderful to have a man love you so much he''d kill for you.', NULL),
  (31822, 845, 'Captain Turley is expecting me.', NULL),
  (31823, 845, 'We''ve found the man you spoke with on the train.', NULL),
  (31824, 845, 'But, we were sitting opposite each other...', NULL),
  (31825, 845, 'Isn''t that proof of where I was at 9:30 last night?', NULL),
  (31826, 845, 'You mean the professor was boiled?', NULL),
  (31827, 845, 'They''re acting as if you were guilty.', NULL),
  (31828, 845, 'Is he likely to picket my office?', NULL),
  (31829, 845, 'You mustn''t do anything that looks suspicious.', NULL),
  (31830, 845, 'You mean we''ll be going together, Hennessy?', NULL),
  (31831, 845, 'We''ve actually been alone for an hour.', NULL),
  (31832, 845, 'Listen, you- There''s a detective outside.', NULL),
  (31833, 845, 'Yes, if I can get a court at the club.', NULL),
  (31834, 845, 'Antony has been telling us some charming stories.', NULL),
  (31835, 845, 'Delightful to see you, Barbara.', NULL),
  (31836, 845, 'Doesn''t that bloodhound ever relax?', NULL),
  (31837, 845, 'Don''t forget your sleeping bag.', NULL),
  (31838, 845, 'She''ll send a butler to defrost you.', NULL),
  (31839, 845, 'I don''t remember inviting him.', NULL),
  (31840, 845, 'When convicted, he''s sentenced.', NULL),
  (31841, 845, 'No more than you, for instance.', NULL),
  (31842, 845, 'Bang, bang, bang, all over the place?', NULL),
  (31843, 845, 'May I borrow your neck for a moment?', NULL),
  (31844, 845, 'I thought he was weird when he arrived.', NULL),
  (31845, 845, 'I was on a merry-go-round somewhere.', NULL),
  (31846, 845, 'What did I have to do with it?', NULL),
  (31847, 845, 'She looked something like Barbara, didn''t she?', NULL),
  (31848, 845, 'He suggested if he got rid of Miriam for me, I should kill his father.', NULL),
  (31849, 845, 'You mean, you''ve known about Miriam all this time?', NULL),
  (31850, 845, 'And Bruno would say we planned it together.', NULL),
  (31851, 845, 'If we could only talk to father, to- It''s not good.', NULL),
  (31852, 845, 'Yes, I want to get this thing over with.', NULL),
  (31853, 845, 'I was about to tell you that on the phone.', NULL),
  (31854, 845, 'Well, then, you''ll have no further use for my key.', NULL),
  (31855, 845, 'Since you profit by it, I think you should be the one to pay for it.', NULL),
  (31856, 845, 'I didn''t even know he was gone...', NULL),
  (31857, 845, 'Just stay put till I get back here.', NULL),
  (31858, 845, 'I''m sure that this whole thing is just some practical joke.', NULL),
  (31859, 845, 'Well, now, Miss Morton, it''s very nice of you to call...', NULL),
  (31860, 845, 'She''s a little, how should I say?', NULL),
  (31861, 845, 'He''s led you up the garden path, I''m afraid.', NULL),
  (31862, 845, 'But of course, I couldn''t do it.', NULL),
  (31863, 845, 'That lie about the lighter means he''ll put it on that island.', NULL),
  (31864, 845, 'Guy, you''ve got to get to Metcalf before he does.', NULL),
  (31865, 845, 'But, darling, that''ll be too late.', NULL),
  (31866, 845, 'If I can finish in three sets, I''ll still- You''re on in a few minutes, Guy.', NULL),
  (31867, 845, 'Ladies and gentlemen, your attention, please.', NULL),
  (31868, 845, 'I wish I understood what this is all about.', NULL),
  (31869, 845, 'I guess we could phone the city engineer.', NULL),
  (31870, 845, 'But you''ll be with Guy, won''t you?', NULL),
  (31871, 845, 'What time does it get dark, I said.', NULL),
  (31872, 845, 'The smoochers wouldn''t go near the place.', NULL),
  (31873, 845, 'I guess he can make it all right.', NULL),
  (31874, 845, 'He wanted to plant it on the island, to pin the whole thing on me.', NULL),
  (31875, 845, 'It''s on the island where you left it.', NULL),
  (31876, 845, 'Besides, he says he hasn''t got it.', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (33477, 872, 'It''s that famous "zip" girl of the screen...', NULL),
  (33478, 872, 'They''ve been married two months already, but still as happy as newlyweds.', NULL),
  (33479, 872, 'Lina and I have no statement to make at the present time.', NULL),
  (33480, 872, 'I want your story from the beginning.', NULL),
  (33481, 872, 'Well, to begin with, any story of my career...', NULL),
  (33482, 872, 'They sent me to the finest schools, including dancing school.', NULL),
  (33483, 872, 'They used to make such a fuss over me.', NULL),
  (33484, 872, 'We played the finest symphonic halls in the country.', NULL),
  (33485, 872, 'We sorted them out and decided to favor Monumental Pictures.', NULL),
  (33486, 872, 'It''ll take hours to get a new one from Central Casting.', NULL),
  (33487, 872, 'And remember, Lockwood, you might be trading that fiddle in for a harp.', NULL),
  (33488, 872, 'Lina was, as always, an inspiration to me.', NULL),
  (33489, 872, 'I just saw some rushes and asked Dexter who the stuntmen were.', NULL),
  (33490, 872, 'Lina and I have had the same wonderful relationship ever since.', NULL),
  (33491, 872, 'Thank you, thank you, thank you.', NULL),
  (33492, 872, 'We screen actors aren''t much good at speaking in public.', NULL),
  (33493, 872, 'Audiences think you got a voice to match.', NULL),
  (33494, 872, 'No, it''s just that Don''s had so much more experience...', NULL),
  (33495, 872, 'Donnie, how can you let him talk to me like that, your fiance?', NULL),
  (33496, 872, 'Now, try to get this straight: There is nothing between us.', NULL),
  (33497, 872, 'Can''t that girl take a gentle hint?', NULL),
  (33498, 872, 'I''ve seen your picture in the paper or in the post office.', NULL),
  (33499, 872, 'I''d like to know whose hospitality I''m enjoying.', NULL),
  (33500, 872, 'Well, we movie stars get the glory...', NULL),
  (33501, 872, 'Which of my pictures have you seen?', NULL),
  (33502, 872, 'Here we are, Sunset and Camden.', NULL),
  (33503, 872, 'I could brush up on my English or bring an interpreter.', NULL),
  (33504, 872, 'Laugh if you want, but the stage is a dignified profession.', NULL),
  (33505, 872, 'I must tear myself from your side.', NULL),
  (33506, 872, 'As long as I work for Monumental, you''re the greatest.', NULL),
  (33507, 872, 'No kidding, folks, aren''t they great?', NULL),
  (33508, 872, 'Note how my lips and the sound issuing from them...', NULL),
  (33509, 872, 'I want you kiddies to have the first piece.', NULL),
  (33510, 872, 'Now that I know where you live, I''d like to see you home.', NULL),
  (33511, 872, 'Here''s one thing I''ve learned from the movies!', NULL),
  (33512, 872, 'She''s a simple girl of the people and won''t even give you a tumble.', NULL),
  (33513, 872, 'You still thinking about that?', NULL),
  (33514, 872, 'Donald Lockwood''s an actor, isn''t he?', NULL),
  (33515, 872, 'The world''s so full Of a number of things I''m sure we should all Be as happy as...', NULL),
  (33516, 872, 'Make''em laugh Make''em laugh Make''em laugh Make''em laugh Make''em laugh Make''em laugh Ready, Don?', NULL),
  (33517, 872, 'I looked for you at Wally Ray''s party.', NULL),
  (33518, 872, 'I''m the one who got the whipped cream in the kisser.', NULL),
  (33519, 872, 'That''s not all I''m gonna do if I ever get my hands on her.', NULL),
  (33520, 872, 'Sticks and stones may break my bones.', NULL),
  (33521, 872, 'Stop that chitchat, you lovebirds.', NULL),
  (33522, 872, 'Oh, my darling little mammy Down in Alabamy This is no joke.', NULL),
  (33523, 872, 'We''ll put you in as head of the music department.', NULL),
  (33524, 872, 'You''re a dazzling eyeful I featured her before, in lots of nightclub shows.', NULL),
  (33525, 872, 'I''m the girl who hit Miss Lamont with a cake.', NULL),
  (33526, 872, 'Don''t let Lina know she''s on the lot.', NULL),
  (33527, 872, 'But for lunch, don''t you tear a pheasant with Miss Lamont?', NULL),
  (33528, 872, 'I pick them up in the beauty parlor or the dentist''s office...', NULL),
  (33529, 872, 'I did say some awful things that night, didn''t I?', NULL),
  (33530, 872, 'Kathy, seeing you again now that I...', NULL),
  (33531, 872, 'Why, it''s just an empty stage.', NULL),
  (33532, 872, 'Now let me hear you read your line.', NULL),
  (33533, 872, 'She''s gotta talk into the mike.', NULL),
  (33534, 872, 'We''re all nervous the first day.', NULL),
  (33535, 872, 'We''re missing every other word.', NULL),
  (33536, 872, 'Now let''s hear how it sounds, Lina.', NULL),
  (33537, 872, 'And whatever you say goes through the wire onto the record.', NULL),
  (33538, 872, 'I am the noblest lady of the court, second only to the queen.', NULL),
  (33539, 872, 'All the ladies of the court wish they were in your shoes.', NULL),
  (33540, 872, 'They will surely find you out.', NULL),
  (33541, 872, 'What you hitting him with, a blackjack?', NULL),
  (33542, 872, 'Did somebody get paid for writing that?', NULL),
  (33543, 872, 'We''re booked to open in six weeks all over the country.', NULL),
  (33544, 872, 'It''ll be up for auction in the morning.', NULL),
  (33545, 872, 'Everything you said about me is true.', NULL),
  (33546, 872, 'With your looks, you could drive an ice wagon.', NULL),
  (33547, 872, 'Fellas, I feel this is my lucky day, March 23rd.', NULL),
  (33548, 872, 'I''m sorry, I was just thinking.', NULL),
  (33549, 872, 'Good mornin'' Good mornin'' to you Watch my mouth.', NULL),
  (33550, 872, 'Well, all right, if it''s only for this one picture, but...', NULL),
  (33551, 872, 'We''ll keep it secret until we''re ready to release...', NULL),
  (33552, 872, 'We need modern musical numbers.', NULL),
  (33553, 872, 'He dreams he''s back during the French Revolution.', NULL),
  (33554, 872, 'He holds her in his arms Would you?', NULL),
  (33555, 872, 'And if the girl were I Would you?', NULL),
  (33556, 872, 'First, we set the stage with a song.', NULL),
  (33557, 872, 'I can''t wait till this picture''s finished.', NULL),
  (33558, 872, 'I want that girl off the lot at once!', NULL),
  (33559, 872, 'Everybody knows you''re in love with me.', NULL),
  (33560, 872, 'As far as I can see, she''s the only one who''s finished.', NULL),
  (33561, 872, 'And she''s getting full screen credit for it too.', NULL),
  (33562, 872, 'They can''t make a laughingstock out of Lina Lamont.', NULL),
  (33563, 872, 'We were prepared for the Selden campaign.', NULL),
  (33564, 872, 'You''ll never get away with it.', NULL),
  (33565, 872, 'What do you think I am, dumb or something?', NULL),
  (33566, 872, 'The studio is responsible for every word printed about me.', NULL),
  (33567, 872, 'We better take Kathy''s credit card off the screen.', NULL),
  (33568, 872, 'You want me to change the name of the studio to Lamont Pictures, Inc?', NULL),
  (33569, 872, 'I wouldn''t do that to her in a million years.', NULL),
  (33570, 872, 'I''ll kiss her with a sigh Would you?', NULL),
  (33571, 872, 'I mean she''s gonna go right on singing for me.', NULL),
  (33572, 872, 'You won''t give all that up because a nobody don''t wanna be my voice.', NULL),
  (33573, 872, 'Producer, always running things, running me.', NULL),
  (33574, 872, 'Yeah, everybody''s always making speeches for me.', NULL),
  (33575, 872, 'She didn''t sound that way in the picture.', NULL),
  (33576, 872, 'But I never want to see you again...', NULL),
  (37077, 975, 'Well, I''ve tried to create a pleasant atmosphere in which to work.', NULL),
  (37078, 975, 'It''s top-secret and must go no further than your chief of staff, and not to him unless you can trust his discretion.', NULL),
  (37079, 975, 'It''s the key to the whole German position in this sector.', NULL),
  (37080, 975, 'Paul, if there''s one man in this army who can do this for me, it''s you.', NULL),
  (37081, 975, 'However, I''m sure you''ll misunderstand my motives in mentioning it.', NULL),
  (37082, 975, 'No one would question your opinion.', NULL),
  (37083, 975, 'What is my ambition against that?', NULL),
  (37084, 975, 'So, you think this attack is absolutely beyond the ability of your men at this time?', NULL),
  (37085, 975, 'You are the man to take the Ant Hill.', NULL),
  (37086, 975, 'Working over your rifle, I see.', NULL),
  (37087, 975, 'Sergeant, I want you to immediately transfer this baby out of my regiment!', NULL),
  (37088, 975, 'I think the fighting spirit of the 701st derives from it.', NULL),
  (37089, 975, 'I can hardly get him behind a desk to sign an order.', NULL),
  (37090, 975, 'But if he wants to be a soldier, then by heavens, he''s got to be one.', NULL),
  (37091, 975, 'Well, I''ve seen much more formidable objectives.', NULL),
  (37092, 975, 'Tell me, Colonel, how did your relief come off last night?', NULL),
  (37093, 975, 'Colonel, your regiment is going to take the Ant Hill tomorrow.', NULL),
  (37094, 975, 'Let''s say another 25 percent in actually taking the Ant Hill.', NULL),
  (37095, 975, 'I''m depending on you, Colonel.', NULL),
  (37096, 975, 'What did he have to say about patriotism?', NULL),
  (37097, 975, 'I''m ordering you on indefinite furlough.', NULL),
  (37098, 975, 'Naturally, I don''t want to relieve you, but I must have enthusiastic support.', NULL),
  (37099, 975, 'There''ll only be the three of us, and we''re to avoid a fight if we can.', NULL),
  (37100, 975, 'I can always tell when he''s had a few.', NULL),
  (37101, 975, 'The lane through our wire is right out in front here.', NULL),
  (37102, 975, 'You''re speaking to an officer.', NULL),
  (37103, 975, 'How do you think those charges are going to look on paper?', NULL),
  (37104, 975, 'Whose word are they going to accept?', NULL),
  (37105, 975, 'Honestly, I know you don''t like me, but what kind of a man do you think I am?', NULL),
  (37106, 975, 'If, or perhaps I should say when, we take the Ant Hill, how long do we have to hold it before we can expect any support?', NULL),
  (37107, 975, 'He''s seen photos of gas cases, but it doesn''t mean anything to me.', NULL),
  (37108, 975, 'Because I know that it can chew you up worse than anything else.', NULL),
  (37109, 975, 'You''re too smart for me, Professor.', NULL),
  (37110, 975, 'They''re still in the trenches!', NULL),
  (37111, 975, 'With all respect, sir, you have no right to order me to shoot down my own men unless you are willing to take full and undivided responsibility for it.', NULL),
  (37112, 975, 'Report yourself under arrest to my headquarters!', NULL),
  (37113, 975, 'Sir, I respectfully submit to the colonel.', NULL),
  (37114, 975, 'Your troops refused to attack.', NULL),
  (37115, 975, 'Colonel Dax, I''m going to have ten men from each company in your regiment tried under penalty of death for cowardice.', NULL),
  (37116, 975, 'If you continue in this manner, I shall have to place you under arrest.', NULL),
  (37117, 975, 'My only aim is to remind you of the heroism these men have shown on every occasion in the past.', NULL),
  (37118, 975, 'We can''t leave it up to the men to decide whether an order is possible.', NULL),
  (37119, 975, 'You''re missing the point entirely.', NULL),
  (37120, 975, 'Paul, we don''t want to overdo this thing.', NULL),
  (37121, 975, 'Let''s get it settled once and for all so we can all live with it.', NULL),
  (37122, 975, 'It''s the only mistake I can ever be accused of.', NULL),
  (37123, 975, 'George, I''m afraid the colonel won''t have time.', NULL),
  (37124, 975, 'I shall look forward to the pleasure of seeing you again.', NULL),
  (37125, 975, 'Shelving will be the best discipline for him in my opinion.', NULL),
  (37126, 975, 'I''ll find an excuse, and I''ll break you to the ranks.', NULL),
  (37127, 975, 'But Lieutenant Roget killed Lejeune on that patrol and then blackmailed me into keeping quiet about it!', NULL),
  (37128, 975, 'I was picked purely by chance.', NULL),
  (37129, 975, 'Now remember, you''ll be soldiers in the presence of superior officers, so act like what you are.', NULL),
  (37130, 975, 'Don''t whine, plead, or make speeches.', NULL),
  (37131, 975, 'Please don''t take up the court''s time with technicalities.', NULL),
  (37132, 975, 'You advanced to the middle of no-man''s-land.', NULL),
  (37133, 975, 'I guess the rest of them had been killed or wounded.', NULL),
  (37134, 975, 'I don''t see the point of this line of questioning.', NULL),
  (37135, 975, 'Yes, sir, until I was ordered back to the trenches by Captain Renouart.', NULL),
  (37136, 975, 'Now, Private Arnaud, before you were ordered back, did you urge your fellow soldiers forward?', NULL),
  (37137, 975, 'Is it true that you''ve been designated a coward simply and purely because you drew a slip of paper marked "X"?', NULL),
  (37138, 975, 'May I call witnesses to his character?', NULL),
  (37139, 975, 'And were you lying unconscious in the trenches during the entire attack?', NULL),
  (37140, 975, 'Prosecutor, you can make your plea.', NULL),
  (37141, 975, 'Colonel, would you like to make your plea?', NULL),
  (37142, 975, 'I protest against being prevented from introducing evidence that I consider vital to the defense.', NULL),
  (37143, 975, 'Any sign of trouble, the prisoners will be instantly covered, and if the trouble doesn''t subside at once, the prisoner will be shot.', NULL),
  (37144, 975, 'Is this supposed to be our last meal or something?', NULL),
  (37145, 975, 'Like, uh, like something to make us groggy or something.', NULL),
  (37146, 975, 'Listen, we got to get out of here.', NULL),
  (37147, 975, 'We''re not going to get out of this.', NULL),
  (37148, 975, 'You must prepare for the worst.', NULL),
  (37149, 975, 'Do you want me to hear your confession?', NULL),
  (37150, 975, 'Have faith in your creator, my son.', NULL),
  (37151, 975, 'May I tell you something, Father?', NULL),
  (37152, 975, 'That''s a nasty skull fracture, though.', NULL),
  (37153, 975, 'Sergeant Boulanger said you wanted to see me, sir.', NULL),
  (37154, 975, 'You picked him because he was a coward, didn''t you?', NULL),
  (37155, 975, 'Would you like me to open a window?', NULL),
  (37156, 975, 'Sir, I request that I be excused from this duty.', NULL),
  (37157, 975, 'I must apologize for not inviting you to the party tonight, but I''m afraid that it''s a dress affair.', NULL),
  (37158, 975, 'How can you understand that and allow these men to be shot tomorrow?', NULL),
  (37159, 975, 'On the other hand, if your men had been more daring, they might have taken it.', NULL),
  (37160, 975, 'It''s been a pleasure discussing this with you, Colonel, but I''m afraid that I''d better be getting back to my guests.', NULL),
  (37161, 975, 'Do you actually believe this fantastic story?', NULL),
  (37162, 975, 'I''ve been rude to my guests too long.', NULL),
  (37163, 975, 'How do you want to be remembered?', NULL),
  (37164, 975, 'What do I have to die for, Father?', NULL),
  (37165, 975, 'He said, "This day, thou shalt be with me in paradise.', NULL),
  (37166, 975, 'But this had splendor, don''t you think?', NULL),
  (37167, 975, 'Colonel Dax, your men died very well.', NULL),
  (37168, 975, 'I think it''s absolutely infamous.', NULL),
  (37169, 975, 'I''m certain you''ll come through it all right.', NULL),
  (37170, 975, 'The man you stabbed in the back is a soldier.', NULL),
  (37171, 975, 'You''ve been after the job from the start.', NULL),
  (37172, 975, 'A promotion you have so very carefully planned for.', NULL),
  (37173, 975, 'I apologize for not revealing my true feelings.', NULL),
  (37174, 975, 'You really did want to save those men, and you were not angling for Mireau''s command.', NULL),
  (37175, 975, 'You bring charges against General Mireau, so I insist he answer them.', NULL),
  (37176, 975, 'Now, gentlemen, I give you our latest acquisition from the enemy.', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (59155, 3112, 'Your Book is full of killings.', NULL),
  (59156, 3112, 'First, swear you''ll take care of little Pearl.', NULL),
  (59157, 3112, 'And I won''t never tell about the money.', NULL),
  (59158, 3112, 'Sleep tight and don''t let the bedbugs bite.', NULL),
  (59159, 3112, 'Ain''t it a caution what a woman will load onto a man''s back...', NULL),
  (59160, 3112, 'He told me lots and lots of things.', NULL),
  (59161, 3112, 'Clear that evil mud out of your soul.', NULL),
  (59162, 3112, 'Powell has something to tell you.', NULL),
  (59163, 3112, 'Won''t it bust it, Uncle Birdie?', NULL),
  (59164, 3112, 'There, you slimy, snag-toothed, bait-stealin'' so-and-so!', NULL),
  (59165, 3112, 'Mom gets mad when she plays out here and don''t put it away.', NULL),
  (59166, 3112, 'Well, I reckon I''ll have to try again.', NULL),
  (59167, 3112, 'We just can''t have anything to do with John.', NULL),
  (59168, 3112, 'I thought if you went and talked to him - you know, another man.', NULL),
  (59169, 3112, 'No, I''m no good at - Get in there.', NULL),
  (59170, 3112, 'It s mighty brave of you, Preacher.', NULL),
  (59171, 3112, 'I reckon I''m safe in promisin'' you that.', NULL),
  (59172, 3112, 'You and me is runnin'' off tonight.', NULL),
  (59173, 3112, 'Powell, don''t be afraid to call on us.', NULL),
  (59174, 3112, 'I promised John I wouldn''t tell.', NULL),
  (59175, 3112, 'But you was worried too, Mother.', NULL),
  (59176, 3112, 'Most of them ain''t fit to go to market.', NULL),
  (59177, 3112, 'If you ain''t a sight to beat all.', NULL),
  (59178, 3112, 'So I''ve got two more mouths to feed.', NULL),
  (59179, 3112, 'What happened to my milk supply?', NULL),
  (59180, 3112, 'I''m saving up to buy you a charm bracelet.', NULL),
  (59181, 3112, 'She can''t get eggs without bustin'' them.', NULL),
  (59182, 3112, 'Next time, I won''t even ask him to buy me an ice cream.', NULL),
  (59183, 3112, 'You are a good woman, Miz Cooper.', NULL),
  (59184, 3112, 'And he ain''t no preacher neither.', NULL),
  (59185, 3112, 'And that''s where the queen found ''im in the "billy rushes.', NULL),
  (59186, 3112, 'That wasn''t the same story at all.', NULL),
  (59187, 3112, 'That''s none of your business, madam.', NULL),
  (59188, 3112, 'And he killed every last one of ''em!', NULL),
  (59189, 3112, 'You can take the little fellow away.', NULL),
  (59190, 3112, 'You don''t mean to say you got me a present?', NULL),
  (67820, 6844, 'To fill in those missing years, we turned to ancient historians such as Philo and Josephus.', NULL),
  (67821, 6844, 'God of Abraham, take my child into thy hands, that he may live to thy service.', NULL),
  (67822, 6844, 'Your husband is in the house of the dead.', NULL),
  (67823, 6844, 'You will see him walk with his head among the eagles.', NULL),
  (67824, 6844, 'Is it the princess'' beauty that attracts you, Rameses, or the fact that she must marry the man I choose to follow me on the throne?', NULL),
  (67825, 6844, 'The trumpets tell all the world he''s come back to me.', NULL),
  (67826, 6844, 'Command what you have conquered, my brother.', NULL),
  (67827, 6844, 'The stiff-necked slaves die more willingly than bend their backs in your service.', NULL),
  (67828, 6844, 'Then you, too, shall go to Goshen- Learn if this deliverer be a myth or a man.', NULL),
  (67829, 6844, 'Now, the flame you lighted burns close to the throne.', NULL),
  (67830, 6844, 'You, there''s other swine to water.', NULL),
  (67831, 6844, 'You''re Dathan, the Hebrew overseer.', NULL),
  (67832, 6844, 'We don''t stop a moving block for an old woman.', NULL),
  (67833, 6844, 'You know it is death to strike an Egyptian?', NULL),
  (67834, 6844, 'Is there any grain stored here in Goshen?', NULL),
  (67835, 6844, 'Well, you know, crowns are sometimes lost by smiles and dimples.', NULL),
  (67836, 6844, 'Cause now he holds Ethiopia in his left hand, Goshen in his right, and you, my Pharaoh, are in between them.', NULL),
  (67837, 6844, 'You would turn Sethi against me.', NULL),
  (67838, 6844, 'And I will enjoy that very much.', NULL),
  (67839, 6844, 'There is the obelisk of your jubilee.', NULL),
  (67840, 6844, 'Are these slaves loyal to Sethi''s glory, or to you, Moses?', NULL),
  (67841, 6844, 'Will you lose the throne because Moses builds a city?', NULL),
  (67842, 6844, 'Why should a slave care which Pharaoh rules?', NULL),
  (67843, 6844, 'You think I care whose son he is?', NULL),
  (67844, 6844, 'What is the death of one slave to us?', NULL),
  (67845, 6844, 'How could Rameses destroy me with a piece of cloth?', NULL),
  (67846, 6844, 'I''ll believe anything you want me to believe.', NULL),
  (67847, 6844, 'Put away any fears or suspicions that may remain with you, my son.', NULL),
  (67848, 6844, 'We are Levites, appointed shepherds of Israel.', NULL),
  (67849, 6844, 'No, I will not take from him the glory and riches you have given him.', NULL),
  (67850, 6844, 'You were the woman who was caught between the stones.', NULL),
  (67851, 6844, 'Will you swear in the name of this god that you are not my mother?', NULL),
  (67852, 6844, 'Has she done more for you than I?', NULL),
  (67853, 6844, 'Back to work, you braying mules.', NULL),
  (67854, 6844, 'She is not worthy of your magnificence.', NULL),
  (67855, 6844, 'But death is better than bondage, for my days are ended and my prayer unanswered.', NULL),
  (67856, 6844, 'Do you think they could bend them?', NULL),
  (67857, 6844, 'And hide the truth from Sethi?', NULL),
  (67858, 6844, 'First I have a call to make on the master builder.', NULL),
  (67859, 6844, 'You women take water to the roof.', NULL),
  (67860, 6844, 'You''ve seen me drive my chariot.', NULL),
  (67861, 6844, 'Why does a prince of Egypt kill the Pharaoh''s master builder to save a Hebrew?', NULL),
  (67862, 6844, 'I have paid you much and you have brought me nothing.', NULL),
  (67863, 6844, 'No, I will not haggle, great prince.', NULL),
  (67864, 6844, 'If not, I will give you the point of this blade through your lying throat.', NULL),
  (67865, 6844, 'Shall I summon him to Pharaoh''s justice?', NULL),
  (67866, 6844, 'What has turned you against me?', NULL),
  (67867, 6844, 'When I cross the river of death, you will be Pharaoh in Egypt.', NULL),
  (67868, 6844, 'I will not make him a martyr for you to cherish.', NULL),
  (67869, 6844, 'Dathan, if you fear God, let me go.', NULL),
  (67870, 6844, 'What would you do to influence His Excellency''s clemency?', NULL),
  (67871, 6844, 'I wish sheep could learn to water themselves.', NULL),
  (67872, 6844, 'Let me first remove his sandals!', NULL),
  (67873, 6844, 'He who has no name surely guided your steps.', NULL),
  (67874, 6844, 'And there are seven here to teach you the tasks of a shepherd.', NULL),
  (67875, 6844, 'My father has many flocks, and no son to tend them.', NULL),
  (67876, 6844, 'Why are you dressed like that?', NULL),
  (67877, 6844, 'Can a man choose from among the stars of the sky?', NULL),
  (67878, 6844, 'We are not dressed in gold and fine linen.', NULL),
  (67879, 6844, 'I''m afraid he won''t let me cheat the way you do.', NULL),
  (67880, 6844, 'The same God who lives on the mountain?', NULL),
  (67881, 6844, 'You must lead them out of Egypt!', NULL),
  (67882, 6844, 'Who am I, Lord, that you should send me?', NULL),
  (67883, 6844, 'Thou shalt say, "I am hath sent me unto you.', NULL),
  (67884, 6844, 'Thus sayeth the Lord God of Israel, "Let my people go!', NULL),
  (67885, 6844, 'You gave me this staff to rule over scorpions and serpents, but God made it a rod to rule over kings.', NULL),
  (67886, 6844, 'Moses, what have you done to us?', NULL),
  (67887, 6844, 'You believe you''ve changed, but you haven''t.', NULL),
  (67888, 6844, 'Because I am bound to a God and to a people and to a shepherd girl.', NULL),
  (67889, 6844, 'Who else can soften Pharaoh''s heart?', NULL),
  (67890, 6844, 'You have not yet obeyed the Lord.', NULL),
  (67891, 6844, 'The people have been plagued by thirst, they''ve been plagued by frogs, by lice, by flies, by sickness, by boils.', NULL),
  (67892, 6844, 'You shall see darkness cover Egypt when the sun climbs high to noon.', NULL),
  (67893, 6844, 'We fear no army of the Earth, but can we fight plagues with swords?', NULL),
  (67894, 6844, 'Do you hear laughter, Rameses?', NULL),
  (67895, 6844, 'As your father''s father turned the streets of Goshen red with the blood of our male children!', NULL),
  (67896, 6844, 'You have been able to erase it?', NULL),
  (67897, 6844, 'Everything about us is coming to an end!', NULL),
  (67898, 6844, 'In the hardness of his heart, Pharaoh has mocked God and brings death to his own son!', NULL),
  (67899, 6844, 'No, Lilia, death will not come to you.', NULL),
  (67900, 6844, 'And under his wing shalt thou trust "Though we stand in the shadow of death, the Lord is our God.', NULL),
  (67901, 6844, 'Tomorrow the light of freedom will shine upon us as we go forth from Egypt.', NULL),
  (67902, 6844, 'The herbs remind us of the bitterness of our captivity, Eleazar.', NULL),
  (67903, 6844, 'You only thought to keep Moses here.', NULL),
  (67904, 6844, 'The power of God has freed us.', NULL),
  (67905, 6844, 'Grandfather, have you got Rebecca?', NULL),
  (67906, 6844, 'Set the standard of each tribe before all the people!', NULL),
  (67907, 6844, 'I''ll pay you back every lash you gave me, Dathan!', NULL),
  (67908, 6844, 'Then let us go forth to the mountain of God, that he may write his commandments in our minds and upon our hearts forever.', NULL),
  (67909, 6844, 'I have raised my voice to you, yet life has not come to the body of my son.', NULL),
  (67910, 6844, 'All that you wanted from me he would not even take.', NULL),
  (67911, 6844, 'I will bring you back your temple treasure!', NULL),
  (67912, 6844, 'Ten times you have seen the miracles of the Lord!', NULL),
  (67913, 6844, 'He opens the waters before them, and he bars our way with fire.', NULL),
  (67914, 6844, 'Better to serve the Egyptians than to die here!', NULL),
  (67915, 6844, 'Moses went up into the forbidden ground to receive God''s law!', NULL),
  (67916, 6844, 'Not if a god of Egypt went before us!', NULL),
  (67917, 6844, 'Thou shalt have no other gods before me.', NULL),
  (67918, 6844, 'We are gathered against you, Moses!', NULL),
  (67919, 6844, 'The Lord was angry with me because I disobeyed him by the waters of strife.', NULL),
  (94760, 10340, 'It''s the one I was admiring, isn''t it?', NULL),
  (94761, 10340, 'She''ll be snug as a bug in a...', NULL),
  (94762, 10340, 'This is where you belong, right here.', NULL),
  (94763, 10340, 'Can''t you explain to Lady about Sundays?', NULL),
  (94764, 10340, 'Yes, I just don''t know how we ever got along without her.', NULL),
  (94765, 10340, 'Won''t Jock and Trusty be surprised?', NULL),
  (94766, 10340, 'Well, I wouldn''t a-be knowin''.', NULL),
  (94767, 10340, 'You know how sensitive he is about these things.', NULL),
  (94768, 10340, 'It shouldn''t have happened to a dog.', NULL),
  (94769, 10340, 'As my grandpappy, Old Reliable, used to say...', NULL),
  (94770, 10340, 'You know, darling, with Lady here I''d say life is quite complete.', NULL),
  (94771, 10340, 'I haven''t been there in a week.', NULL),
  (94772, 10340, 'The boss, he''s a-saving some a-nice bones for you.', NULL),
  (94773, 10340, 'You''re a bit of all right, chum.', NULL),
  (94774, 10340, 'I wonder what the leash and collar set does for excitement.', NULL),
  (94775, 10340, 'Well, I first noticed it the other day when Jim Dear came home.', NULL),
  (94776, 10340, 'He''s never called me that before.', NULL),
  (94777, 10340, 'Remember, they''re only humans, after all.', NULL),
  (94778, 10340, 'But Darling has never struck me...', NULL),
  (94779, 10340, 'What he''s trying to say, lassie, is Darling is expecting a wee bairn.', NULL),
  (94780, 10340, 'You will not be permitted to play with it.', NULL),
  (94781, 10340, 'Move it over, will you, friend?', NULL),
  (94782, 10340, 'You get the urge for a nice comfortable scratch, and, "Put that dog out!', NULL),
  (94783, 10340, 'You start barking at some strange mutt.', NULL),
  (94784, 10340, 'Remember those nice, juicy cuts of beef?', NULL),
  (94785, 10340, 'And we''ve no need for mongrels and their radical ideas.', NULL),
  (94786, 10340, 'There isn''t any way we can tell what it''s going to be, is there?', NULL),
  (94787, 10340, 'That''s the cutest thing I ever saw.', NULL),
  (94788, 10340, 'That''s what I told Bill yesterday.', NULL),
  (94789, 10340, 'It''s a boy, it''s a boy, it''s a boy!', NULL),
  (94790, 10340, 'We''ve got enough here to take us halfway to China.', NULL),
  (94791, 10340, 'If he wakes up we''ll never get away.', NULL),
  (94792, 10340, 'She thinks we''re running out on him.', NULL),
  (94793, 10340, 'Have a good time, and don''t worry about a thing.', NULL),
  (94794, 10340, 'Aunt Sarah won''t let that dog frighten you anymore.', NULL),
  (94795, 10340, 'If we sneaking up upon it carefully...', NULL),
  (94796, 10340, 'Where we finding baby there are milk nearby If we look in baby buggy there could be Plenty milk for you and also some for me What''s going on down there?', NULL),
  (94797, 10340, 'Now, we''ll just slip it on like this, and...', NULL),
  (94798, 10340, 'I think I know the very place.', NULL),
  (94799, 10340, 'I suppose you''ll be tellin'' me next it was the dog that was whistling?', NULL),
  (94800, 10340, 'We better go through this place from A to Z.', NULL),
  (94801, 10340, 'If anybody ever needed a muzzle, it''s him.', NULL),
  (94802, 10340, 'I wonder if you''d do us a little...', NULL),
  (94803, 10340, 'Think the cuttin'' takes the time?', NULL),
  (94804, 10340, 'What you need is a log puller.', NULL),
  (94805, 10340, 'You merely slip this ring over the limb like this, and haul it off.', NULL),
  (94806, 10340, 'How do you get the consarned thing off, sonny?', NULL),
  (94807, 10340, 'Well, friend, we''ll be on our way now, so...', NULL),
  (94808, 10340, 'Oh, no, it''s all yours, friend.', NULL),
  (94809, 10340, 'Well, that''s what comes of tying yourself down to one family.', NULL),
  (94810, 10340, 'Something tells me it''s suppertime.', NULL),
  (94811, 10340, 'Now, O''Brian''s here is where little Mike, that''s me again, Pige, comes every Tuesday.', NULL),
  (94812, 10340, 'You see, Pige, when you''re footloose and collar-free, well, you take nothing but the best.', NULL),
  (94813, 10340, 'Joe, bring some bones for Butchy before he eat me up.', NULL),
  (94814, 10340, 'He''s a got a cockerel Spanish a-girl.', NULL),
  (94815, 10340, 'You take-a Tony''s advice and a-settle down with this-a one?', NULL),
  (94816, 10340, 'Now, first we fix-a the table.', NULL),
  (94817, 10340, 'Tell me, what''s your pleasure?', NULL),
  (94818, 10340, 'Because you still believe in that, "in the faithful old dog tray" routine?', NULL),
  (94819, 10340, 'Look, there''s a great big hunk of world down there with no fence around it.', NULL),
  (94820, 10340, 'And it''s all ours for the taking, Pige.', NULL),
  (94821, 10340, 'It''s a beautiful night And they call it...', NULL),
  (94822, 10340, 'Hey, what''s going on in there?', NULL),
  (94823, 10340, 'You know, there''s a little bit of bird dog in all of us, Pige.', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (94824, 10340, 'Put her in number four, Bill, while I check her license number.', NULL),
  (94825, 10340, 'Hey, whatcha in for, sweetheart?', NULL),
  (94826, 10340, 'Can''t you see the poor kid''s scared enough already?', NULL),
  (94827, 10340, 'It''s like Gorky says in Lower Depths, quote: "Miserable being must find more miserable being.', NULL),
  (94828, 10340, 'There ain''t nothin'' wrong with it.', NULL),
  (94829, 10340, 'That''s your passport to freedom, honey.', NULL),
  (94830, 10340, 'Now there''s a bloke The Tramp?', NULL),
  (94831, 10340, 'He''s given the slip to every dogcatcher in this burg.', NULL),
  (94832, 10340, 'I can quite easily believe that.', NULL),
  (94833, 10340, 'And my sister, Rosita Chiquita Juanita Chihuahua.', NULL),
  (94834, 10340, 'Like Miss Park Avenue here, matey?', NULL),
  (94835, 10340, 'You''re too nice a girl to be in this place.', NULL),
  (94836, 10340, 'But no matter which of us she accepts, we''ll always be the best of friends.', NULL),
  (94837, 10340, 'Please, I don''t want to see anybody.', NULL),
  (94838, 10340, 'We''ve come with a proposition.', NULL),
  (94839, 10340, 'But we''re still in the prime of life.', NULL),
  (94840, 10340, 'Where we know you''ll be welcome and appreciated, Miss Lady.', NULL),
  (94841, 10340, 'Anything new in the kennel club set?', NULL),
  (94842, 10340, 'Looks like I''m the one that''s in the doghouse.', NULL),
  (94843, 10340, 'We''ll gladly throw the rascal out.', NULL),
  (94844, 10340, 'When I heard they''d taken you to the pound...', NULL),
  (94845, 10340, 'Who could ever harm a cute little trick like you?', NULL),
  (94846, 10340, 'As far as I''m concerned, you needn''t worry about your old heel.', NULL),
  (94847, 10340, 'If you grow careless, don''t blame me.', NULL),
  (94848, 10340, 'Thank goodness you''re not hurt.', NULL),
  (94849, 10340, 'I don''t care if you are alone there, young man.', NULL),
  (94850, 10340, 'If you want my advice you''ll destroy that animal at once.', NULL),
  (94851, 10340, 'I was certain he was no good the moment I first laid eyes on him.', NULL),
  (94852, 10340, 'I''m sure there must be some mistake.', NULL),
  (94853, 10340, 'But man, we don''t know which way they''ve gone.', NULL),
  (94854, 10340, 'I guess I used a little too much.', NULL),
  (94855, 10340, 'Darling, where did you put the dog biscuits?', NULL),
  (94856, 10340, 'But there''s a bit of their father in them too.', NULL),
  (94857, 10340, 'Caught the scent the moment I came in the house.', NULL),
  (94858, 10340, 'Course, my sense of smell is very highly developed.', NULL),
  (94859, 10340, 'No, you haven''t, Uncle Trusty.', NULL),
  (98902, 10693, 'We mustn''t be late for the party, you know.', NULL),
  (98903, 10693, 'And if we don''t go to the party, I can never show my face in the office again.', NULL),
  (98904, 10693, 'Oh, Nana, must we always take that nasty tonic?', NULL),
  (98905, 10693, 'Back, back, back, you villain!', NULL),
  (98906, 10693, 'But it did turn out rather nicely, didn''t...', NULL),
  (98907, 10693, 'Well, "Now, George," will have his say!', NULL),
  (98908, 10693, 'And that''s my last word on the matter...', NULL),
  (98909, 10693, 'Dash it all, Nana, don''t look at me like that.', NULL),
  (98910, 10693, 'And the children aren''t puppies.', NULL),
  (98911, 10693, 'I''m sure he didn''t mean it, John.', NULL),
  (98912, 10693, 'After all, he really loves you very much.', NULL),
  (98913, 10693, 'But, George, do you think the children will be safe without Nana?', NULL),
  (98914, 10693, 'How can we expect the children to grow up and be practical...', NULL),
  (98915, 10693, 'Stop playing and help me find my shadow.', NULL),
  (98916, 10693, 'Oh, you can''t stick it on with soap, Peter.', NULL),
  (98917, 10693, 'Although, come to think of it, I''ve never thought about it before.', NULL),
  (98918, 10693, 'And I said to myself, I said, "I''ll put it away for him until he comes back.', NULL),
  (98919, 10693, 'But what I still don''t understand is how Nana got it in the first place.', NULL),
  (98920, 10693, 'Oh, uh, but how did Nana get your shadow, Peter?', NULL),
  (98921, 10693, 'Well, what were you doing there?', NULL),
  (98922, 10693, 'Because I have to grow up tomorrow.', NULL),
  (98923, 10693, 'Oh, and I must leave a note when I''ll be back.', NULL),
  (98924, 10693, 'Oh, well, uh, I-I''ll show you.', NULL),
  (98925, 10693, 'Well, come on, Wendy, let''s go.', NULL),
  (98926, 10693, 'Oh, I should like very much to cross swords with some real buccaneers.', NULL),
  (98927, 10693, 'You think of a wonderful thought.', NULL),
  (98928, 10693, 'I''ll think I''m in a pirate''s cave.', NULL),
  (98929, 10693, 'It''s the same as having wings.', NULL),
  (98930, 10693, 'Here we are, collecting barnacles on this miserable island.', NULL),
  (98931, 10693, 'Why, I''ve almost forgotten how to slit a throat.', NULL),
  (98932, 10693, 'Those redskins know this island better than I do me own ship.', NULL),
  (98933, 10693, 'A pirate''s life is a wonderful I-life You''ll find adventure and sport But live every minute for all that is in it The life of a pirate is short Oh, the life...', NULL),
  (98934, 10693, 'Did Pan show good form when he did this to me?', NULL),
  (98935, 10693, 'But throwing it to the crocodile!', NULL),
  (98936, 10693, 'But now when he''s about, he warns ya as ya might say with his tick-tock...', NULL),
  (98937, 10693, 'There''ll be no handouts today.', NULL),
  (98938, 10693, 'Oh, a pirate''s life is a wonderful life A- sailing over the sea Give me a career as a...', NULL),
  (98939, 10693, 'Now, why don''t we put to sea, see?', NULL),
  (98940, 10693, 'I never shaved him this close before.', NULL),
  (98941, 10693, 'Headed this way with some more of those scurvy brats!', NULL),
  (98942, 10693, 'Man the Long Tom, you bilge rats!', NULL),
  (98943, 10693, 'Double the powder and shorten the fuse!', NULL),
  (98944, 10693, 'Oh, Peter, it''s just as I''ve always dreamed it would be.', NULL),
  (98945, 10693, 'Oh, look, there''s Captain Hook and the pirates.', NULL),
  (98946, 10693, 'Good heavens, Wendy, you might have been killed.', NULL),
  (98947, 10693, 'I bring ya a mother to tell ya stories...', NULL),
  (98948, 10693, 'Well, she said you said to shoot it down!', NULL),
  (98949, 10693, 'But don''t ya know ya might have killed her?', NULL),
  (98950, 10693, 'I shall try to be worthy of my post.', NULL),
  (98951, 10693, 'The initial phase is an encircling manoeuvre, thus!', NULL),
  (98952, 10693, 'Aw, that''s all right, Wildcat.', NULL),
  (98953, 10693, 'When they win, they turn us loose.', NULL),
  (98954, 10693, 'Why did you stay away so long?', NULL),
  (98955, 10693, 'Oh, I''ve always liked that one.', NULL),
  (98956, 10693, 'Oh, please, I''m not dressed for it.', NULL),
  (98957, 10693, 'They were just having a little fun, weren''t you, girls?', NULL),
  (98958, 10693, 'Looks like they''re headin'' for Skull Rock.', NULL),
  (98959, 10693, 'You tell me the hiding place of Peter Pan...', NULL),
  (98960, 10693, 'You''d better talk, me dear, for soon the tide will be in...', NULL),
  (98961, 10693, 'Stand by, Smee, while I take a look around.', NULL),
  (98962, 10693, 'I told him all along you Indians wouldn''t betray Peter Pan.', NULL),
  (98963, 10693, 'Just what you told me, Captain.', NULL),
  (98964, 10693, 'Oh, but, C-Captain, d-d-didn''t you?', NULL),
  (98965, 10693, 'Come down, boy, if you''ve a taste for cold steel.', NULL),
  (98966, 10693, 'I say, Captain, do you hear something?', NULL),
  (98967, 10693, 'Oh, a pirate''s life is a wonderful life Your hot water, Mr Smee.', NULL),
  (98968, 10693, 'Brings back the good old days when we was leadin'' a healthy, normal life.', NULL),
  (98969, 10693, 'Why, you doddering imbecile, I...', NULL),
  (98970, 10693, 'This ain''t no place for a respectable pirate.', NULL),
  (98971, 10693, 'If we impress the pixie, convince her we''re eager to help her...', NULL),
  (98972, 10693, 'T-To tell the boys we sails with the tide, sir.', NULL),
  (98973, 10693, 'He''s delivering an oration in sign language.', NULL),
  (98974, 10693, 'Uh, what makes the red man red?', NULL),
  (98975, 10693, 'I''m glad to hear that, Captain.', NULL),
  (98976, 10693, 'Why, rumour has it that already she has come between you and Peter.', NULL),
  (98977, 10693, 'Mr Smee, we must save the lad from himself.', NULL),
  (98978, 10693, 'Great Scott, you''re right, Smee!', NULL),
  (98979, 10693, 'Aw, Wendy, is that all you have to say?', NULL),
  (98980, 10693, 'Oh, Wendy, we don''t want to go home.', NULL),
  (98981, 10693, 'Do you want to stay here and grow up like...', NULL),
  (98982, 10693, 'Did she have silky ears and wear a fur coat?', NULL),
  (98983, 10693, 'I propose we leave for home at once.', NULL),
  (98984, 10693, 'Uh, that is, if Peter doesn''t mind.', NULL),
  (98985, 10693, 'But I have given me word not to lay a finger...', NULL),
  (98986, 10693, 'But a thousand pardons, my dear.', NULL),
  (98987, 10693, 'You see, we left a present for Peter.', NULL),
  (98988, 10693, 'Why, I can see our little friend at this very moment...', NULL),
  (98989, 10693, 'But I''ve gotta save you first.', NULL),
  (98990, 10693, 'Captain Hook, we will never join your crew.', NULL),
  (98991, 10693, 'So, you want a splash, Mr Starkey.', NULL),
  (98992, 10693, 'It''s his blinkin'' ghost what''s talkin''!', NULL),
  (98993, 10693, 'Don''t stand there, you bilge rats!', NULL),
  (98994, 10693, 'You''d fly away like a cowardly sparrow!', NULL),
  (98995, 10693, 'I''ll fight you man-to-man, with one hand behind my back.', NULL),
  (98996, 10693, 'You wouldn''t do old Hook in now, would you, lad?', NULL),
  (98997, 10693, 'After all, she''s still a child.', NULL),
  (98998, 10693, 'Wendy, what on earth are you doing there?', NULL),
  (98999, 10693, 'Well, my dear, all in good time.', NULL),
  (99000, 10693, 'I knew Peter Pan would save us, and he did.', NULL),
  (99001, 10693, 'And then we sailed away on a ship in the sky.', NULL),
  (100571, 10882, 'And our story begins on that most joyful day.', NULL),
  (100572, 10882, 'Their Royal Highnesses, King Hubert and Prince Phillip!', NULL),
  (100573, 10882, 'Their most honoured and exalted excellencies, the Three Good Fairies!', NULL),
  (100574, 10882, 'Little Princess, my gift shall be the gift of beauty.', NULL),
  (100575, 10882, 'One gift Beauty rare Gold of sunshine In her hair Lips that shame the red, red rose She''ll walk with springtime Wherever she goes Tiny Princess, my gift shall be the gift of song.', NULL),
  (100576, 10882, 'I really felt quite distressed at not receiving an invitation.', NULL),
  (100577, 10882, 'I had hoped it was merely due to some oversight.', NULL),
  (100578, 10882, 'Well, in that event, I''d best be on my way.', NULL),
  (100579, 10882, 'And to show I bear no ill will, I, too, shall bestow a gift on the child.', NULL),
  (100580, 10882, 'Don''t despair, Your Majesties.', NULL),
  (100581, 10882, 'And from this slumber you shall wake...', NULL),
  (100582, 10882, 'I''m sure it''ll work out somehow.', NULL),
  (100583, 10882, 'Well, a bonfire won''t stop Maleficent.', NULL),
  (100584, 10882, 'Ooh, I''d like to turn her into a fat, old hoptoad.', NULL),
  (100585, 10882, 'Now, dear, that isn''t a very nice thing to say.', NULL),
  (100586, 10882, 'Well, that would make me happy.', NULL),
  (100587, 10882, 'Oh, she''d make a lovely flower.', NULL),
  (100588, 10882, 'A flower can''t prick its finger.', NULL),
  (100589, 10882, 'And she''ll be expecting us to do something like that.', NULL),
  (100590, 10882, 'Maleficent doesn''t know anything about love...', NULL),
  (100591, 10882, 'It''s the only thing she can''t understand and won''t expect.', NULL),
  (100592, 10882, 'Now, now, now, we''ll have to plan it carefully.', NULL),
  (100593, 10882, 'Well, y-yes, but w-w-we''d have to feed it a...', NULL),
  (100594, 10882, 'If humans can do it, so can we.', NULL),
  (100595, 10882, 'And we''d have our magic to help us.', NULL),
  (100596, 10882, 'We''ve never done anything without magic.', NULL),
  (100597, 10882, 'And that''s why Maleficent will never suspect...', NULL),
  (100598, 10882, 'She couldn''t have vanished into thin air!', NULL),
  (100599, 10882, 'Are you sure you searched everywhere?', NULL),
  (100600, 10882, 'Yeah, we searched mountains, uh, uh, uh, uh, forests...', NULL),
  (100601, 10882, 'Well, now, how about this one?', NULL),
  (100602, 10882, 'Oh, she''ll look beautiful in that.', NULL),
  (100603, 10882, 'And don''t forget a pretty bow.', NULL),
  (100604, 10882, 'Yes, but how are we gonna get her out of the house?', NULL),
  (100605, 10882, 'Well, and what are you three dears up to?', NULL),
  (100606, 10882, 'But I-I picked berries yesterday.', NULL),
  (100607, 10882, 'But I''ve never baked a fancy cake.', NULL),
  (100608, 10882, 'But you can''t sew, and she''s never cooked.', NULL),
  (100609, 10882, 'Well, I still say we ought to use magic.', NULL),
  (100610, 10882, 'That''s for the feet to go through.', NULL),
  (100611, 10882, 'After today, she''ll be a princess, and we won''t have any Briar Rose.', NULL),
  (100612, 10882, 'But why did it have to come so soon?', NULL),
  (100613, 10882, 'We''re acting like a lot of ninnies.', NULL),
  (100614, 10882, 'She''ll be back before we get started.', NULL),
  (100615, 10882, 'They never want me to meet anyone.', NULL),
  (100616, 10882, 'Well, he''s tall and handsome and...', NULL),
  (100617, 10882, 'Oh, we walk together and talk together, and just before we say goodbye, he takes me in his arms...', NULL),
  (100618, 10882, 'You know, Samson, there was something strange about that voice.', NULL),
  (100619, 10882, 'You know, I''m really not supposed to speak to strangers, but we''ve met before.', NULL),
  (100620, 10882, 'Well, what do you think of it?', NULL),
  (100621, 10882, 'It''s a very unusual cake, isn''t it?', NULL),
  (100622, 10882, 'Of course, it''ll be much stiffer after it''s baked.', NULL),
  (100623, 10882, 'I-It''s not exactly the way it is in the book, is it?', NULL),
  (100624, 10882, 'But perhaps if I added a few more ruffles, uh...', NULL),
  (100625, 10882, 'I think we''ve had enough of this nonsense!', NULL),
  (100626, 10882, 'I think we ought to think of Rose and what she''ll think of this mess.', NULL),
  (100627, 10882, 'I still think what I thunk before.', NULL),
  (100628, 10882, 'Uh, Fauna, you close the windows.', NULL),
  (100629, 10882, 'Now, you take care of the cake.', NULL),
  (100630, 10882, 'This is the happiest day of my life.', NULL),
  (100631, 10882, 'I know you I walked with you once upon a dream She''s in love!', NULL),
  (100632, 10882, 'I''m sorry, child, but you must never see that young man again.', NULL),
  (100633, 10882, 'And we thought she''d be so happy.', NULL),
  (100634, 10882, 'It''s a good half hour ''til sunset.', NULL);
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (100635, 10882, 'Tonight, we toast the future...', NULL),
  (100636, 10882, 'Skumps, skumps - Skumps A toast to this night - The outlook is rosy The future is bright Our children will marry Our kingdoms unite Skumps, skumps Skumps Ah, excellent vintage.', NULL),
  (100637, 10882, 'Place to raise their little brood, eh?', NULL),
  (100638, 10882, 'Skumps - Skumps A toast to the home - One grander by far Than a palace in Rome Uh, let me fill up your glass.', NULL),
  (100639, 10882, 'Skumps, skumps Skumps The plans!', NULL),
  (100640, 10882, 'But, Hubert, they''re not even married yet.', NULL),
  (100641, 10882, 'I haven''t even seen my daughter yet, and you''re taking her away from me.', NULL),
  (100642, 10882, 'Want to see our grandchildren, don''t we?', NULL),
  (100643, 10882, 'Why doesn''t your daughter like my son?', NULL),
  (100644, 10882, 'Why, you, you unreasonable, Huh?', NULL),
  (100645, 10882, 'And as for grandchildren, I''ll have the royal woodcarvers start work on the cradle tomorrow.', NULL),
  (100646, 10882, 'His Royal Highness, Prince Phillip!', NULL),
  (100647, 10882, 'Now, what''s all this "dream" nonsense?', NULL),
  (100648, 10882, 'Good heavens, we must tell Stefan.', NULL),
  (100649, 10882, 'I said I met the girl I was going to marry.', NULL),
  (100650, 10882, 'Now, Father, you''re living in the past.', NULL),
  (100651, 10882, 'And I command you to come to your senses!', NULL),
  (100652, 10882, 'I don''t see why she has to marry any old prince.', NULL),
  (100653, 10882, 'Now, that''s not for us to decide, dear.', NULL),
  (100654, 10882, 'Oh, why did we leave her alone?', NULL),
  (100655, 10882, 'You poor, simple fools, thinking you could defeat me.', NULL),
  (100656, 10882, 'Well, here''s your precious princess.', NULL),
  (100657, 10882, 'Make ready to welcome your princess.', NULL),
  (100658, 10882, 'They''ll be heartbroken when they find out.', NULL),
  (100659, 10882, 'We''ve got to get back to the cottage.', NULL),
  (100660, 10882, 'I set my trap for a peasant, and lo, I catch a prince.', NULL),
  (100661, 10882, 'I have plans for our royal guest.', NULL),
  (100662, 10882, 'We must go to the dungeon and cheer him up.', NULL),
  (100663, 10882, 'A wondrous future lies before you.', NULL),
  (100664, 10882, 'Let us leave our noble prince...', NULL),
  (100665, 10882, 'For the first time in sixteen years, I shall sleep well.', NULL),
  (100666, 10882, 'A forest of thorns shall be his tomb, borne through the skies on a fog of doom!', NULL),
  (100667, 10882, 'Round Stefan''s castle cast my spell.', NULL),
  (100668, 10882, 'Now shall you deal with me, O Prince, and all the powers of hell!', NULL),
  (100669, 10882, 'Well, to come right to the point, my son Phillip says he''s going to marry...', NULL),
  (100670, 10882, 'Why, Fauna, what''s the matter, dear?', NULL),
  (103471, 11224, 'Yes, I know it''s a Iovely morning, but...', NULL),
  (103472, 11224, 'Cause if you tell a wish, it won''t come true.', NULL),
  (103473, 11224, 'The dreams that I wish Will come true Shoo!', NULL),
  (103474, 11224, 'Now, Jaq, what''s all the fuss about?', NULL),
  (103475, 11224, 'Jaq, maybe you''d better explain things to him.', NULL),
  (103476, 11224, 'It is a Iittle snug, but it''ll have to do.', NULL),
  (103477, 11224, 'See that he keeps out of trouble, Jaq, and don''t forget to warn him about the cat.', NULL),
  (103478, 11224, 'It''s certainly not my idea to feed you first.', NULL),
  (103479, 11224, 'Suppose they heard you upstairs?', NULL),
  (103480, 11224, 'I know it isn''t easy, but at Ieast we should try to get along together.', NULL),
  (103481, 11224, 'Come on, everybody, breakfee!- Breakfast!', NULL),
  (103482, 11224, 'And don''t be all day getting it done, either!', NULL),
  (103483, 11224, 'Pick up the laundry and get on with your duties.', NULL),
  (103484, 11224, 'Oh, Lucifer, won''t you ever Iearn?', NULL),
  (103485, 11224, 'It seems we have time on our hands.', NULL),
  (103486, 11224, 'Perhaps we can put it to better use.', NULL),
  (103487, 11224, 'But I just fin-- Do them again!', NULL),
  (103488, 11224, 'But, but, but-- No "buts" about it!', NULL),
  (103489, 11224, 'It''s high time he married and settled down.', NULL),
  (103490, 11224, 'I want to see my grandchildren before I go.', NULL),
  (103491, 11224, 'No, no, you don''t know what it means to see...', NULL),
  (103492, 11224, 'I want to hear the pitter-patter of Iittle feet again.', NULL),
  (103493, 11224, 'W-w-with his silly romantic ideas?', NULL),
  (103494, 11224, 'But, but, Your Majesty, if the Prince should suspect-- Suspect?', NULL),
  (103495, 11224, 'If all the eligible maidens in my kingdom just...', NULL),
  (103496, 11224, 'And see that every eligible maid is there!', NULL),
  (103497, 11224, 'Maybe I should interrupt the...', NULL),
  (103498, 11224, 'You''re always-- Girls, girls!- It''s her fault, Mother.', NULL),
  (103499, 11224, 'Give it here!- Let me have it!', NULL),
  (103500, 11224, 'In honour of His Highness, the Prince!', NULL),
  (103501, 11224, 'Would you mind holding my broom?', NULL),
  (103502, 11224, 'After all, I''m still a member of the family.', NULL),
  (103503, 11224, 'And if you can find something...', NULL),
  (103504, 11224, 'It''s pretty-pretty, but its old.', NULL),
  (103505, 11224, 'I''ll have to shorten the sleeves...', NULL),
  (103506, 11224, 'Oh, well, guess my dress will just have to wait.', NULL),
  (103507, 11224, 'She''ll never get her dress done.', NULL),
  (103508, 11224, 'Pretty surprise for Cinderelly!', NULL),
  (103509, 11224, 'Now don''t forget- Cinderella, take my dress!', NULL),
  (103510, 11224, 'Press my skirt too, and mind the ruffle.', NULL),
  (103511, 11224, 'When you''re through, and before you begin your regular chores, I have a few Iittle things.', NULL),
  (103512, 11224, 'Oh, I hate-- I don''t see why I can''t have- Come on!', NULL),
  (103513, 11224, 'Mmmm mm mm believing The dream that you wish will come...', NULL),
  (103514, 11224, 'Why, Cinderella, you''re not ready, child.', NULL),
  (103515, 11224, 'Now remember, when you''re presented to His Highness, be sure-- Wait!', NULL),
  (103516, 11224, 'And I never go back on my word.', NULL),
  (103517, 11224, 'You ungrateful Iittle-- Girls, girls.', NULL),
  (103518, 11224, 'I wont have you upsetting yourselves.', NULL),
  (103519, 11224, 'Have faith in your dreams and someday It''s just no use.', NULL),
  (103520, 11224, 'No matter how your heart is grieving If you keep on believing I can''t believe, not anymore.', NULL),
  (103521, 11224, 'Oh, but I do!- Nonsense, child!', NULL),
  (103522, 11224, 'If you''d Iost all your faith, I couldnt be here, and here I am!', NULL),
  (103523, 11224, 'Oh, but I''m not-- Of course you are.', NULL),
  (103524, 11224, 'What in the world did I do with that magic wand?', NULL),
  (103525, 11224, 'I always-- Why then, you must be-- Your Fairy Godmother?', NULL),
  (103526, 11224, 'Now, with an elegant coach like that, of course, we''ll simply have to have...', NULL),
  (103527, 11224, 'Just a wave of my stick, and to finish the trick, Bibbidi..', NULL),
  (103528, 11224, 'You can''t go to the ball without...', NULL),
  (103529, 11224, 'But tonight, for a change, you''ll handle the reins...', NULL),
  (103530, 11224, 'Bibbidi-bobbidi-boo Oh, it''s a beautiful dress!', NULL),
  (103531, 11224, 'Why, it''s Iike a dream, a wonderful dream come true.', NULL),
  (103532, 11224, 'You''ll have only ''til midnight and then-- Midnight?', NULL),
  (103533, 11224, 'Have a good time, dance, be gay!', NULL),
  (103534, 11224, 'Even I couldnt expect the boy to-- Well, if I may say so, Your Majesty.', NULL),
  (103535, 11224, 'No doubt you saw the whole pretty picture in detail.', NULL),
  (103536, 11224, 'That''s one thing in her favour.', NULL),
  (103537, 11224, 'I believe I too-- You will stay right here.', NULL),
  (103538, 11224, 'But I know I''ve never seen her.', NULL),
  (103539, 11224, 'But didn''t you know-- Goodbye!', NULL),
  (103540, 11224, 'And he was so handsome, and when we danced-- Oh, Im sure that even the Prince himself...', NULL),
  (103541, 11224, 'Thank you so much, for everything.', NULL),
  (103542, 11224, 'I regret to inform you, Sire, that the young Iady has disappeared...', NULL),
  (103543, 11224, 'Well, I didn''t get a chance--- No matter.', NULL),
  (103544, 11224, 'But, but, but-- Better practice passing these out, eh?', NULL),
  (103545, 11224, 'Your, Your Majesty, p-p-please.', NULL),
  (103546, 11224, 'A peculiar title, but if thats what you-- She what?', NULL),
  (103547, 11224, 'All we could find was this glass slipper.', NULL),
  (103548, 11224, 'He won''t rest ''til he finds her.', NULL),
  (103549, 11224, 'I''ll have nothing to do with it.', NULL),
  (103550, 11224, 'Bring up the breakfast trays at once, and hurry!', NULL),
  (103551, 11224, 'Clean that up, and then help my daughters dress.', NULL),
  (103552, 11224, 'If hes in Iove with that girl, why should we even bother?', NULL),
  (103553, 11224, 'Why, Mother, what do you mean?', NULL),
  (103554, 11224, 'Never mind her, mend these right away!', NULL),
