INSERT INTO quotes (id, movie_id, text, character) VALUES
  (110535, 12092, 'Why, this clock is exactly two days slow Two days slow?', NULL),
  (110536, 12092, 'I see what''s wrong with this Why, this watch is full of wheels Oh, my poor watch.', NULL),
  (110537, 12092, 'Two spoons Thank you, yes Oh, please be careful!', NULL),
  (110538, 12092, 'Just shows you what a person''ll do Mustard?', NULL),
  (110539, 12092, 'There''s only one way to stop a mad watch Two days slow.', NULL),
  (110540, 12092, 'A very merry unbirthday to us, to us Of all the silly nonsense This is the stupidest tea party I''ve ever been to in all my life Well, I''ve had enough nonsense I''m going home.', NULL),
  (110541, 12092, 'Why, if it hadn''t been for him, I...', NULL),
  (110542, 12092, 'When I get home, I shall write a book about this place If I...', NULL),
  (110543, 12092, 'It''s getting dreadfully dark And nothing looks familiar I shall certainly be glad to get out of...', NULL),
  (110544, 12092, 'I just knew I''d find one sooner or later If I hurry fast, I might even be home in time for tea Oh.', NULL),
  (110545, 12092, 'Now I shall never get out Well, when...', NULL),
  (110546, 12092, 'I- I-I''m through with rabbits I wanna go home!', NULL),
  (110547, 12092, 'Simply mad And the mome raths outgrabe Please, please!', NULL),
  (110548, 12092, 'One, two, three, four, five, six, seven, eight, nine, ten, jack!', NULL),
  (110549, 12092, 'Who''s been painting my roses red?', NULL),
  (110550, 12092, 'Well, well, now, uh, uh, let me see, my dear It certainly isn''t a heart.', NULL),
  (110551, 12092, 'Speak nicely And don''t twiddle your fingers!', NULL),
  (110552, 12092, 'W- Well, I-I''m trying to find my way home Your way?', NULL),
  (110553, 12092, 'But I was only going to ask...', NULL),
  (110554, 12092, 'By order of the King Uh, you heard what she said You''re next, my dear Oh, but...', NULL),
  (110555, 12092, 'Uh-huh Well, I don''t Uh, I say, how are you getting on?', NULL),
  (110556, 12092, 'I warn you, child, if I lose my temper, you lose your head!', NULL),
  (110557, 12092, 'Save the Queen Someone''s head will roll for this!', NULL),
  (110558, 12092, 'Very well, then Let the trial begin!', NULL),
  (110559, 12092, 'Verdict afterwards But that just isn''t the way!', NULL),
  (110560, 12092, 'Eh, we''ve called no witnesses Huh?', NULL),
  (110561, 12092, 'Jury, write that down Uh, unimportant, uh, Your Majesty means of course Silence!', NULL),
  (110562, 12092, 'That''s the most important piece of evidence we''ve heard yet Write that down!', NULL),
  (110563, 12092, 'I was home drinking tea Today, you know, is my unbirthday Why, my dear, today is your unbirthday too It is?', NULL),
  (110564, 12092, 'A very merry unbirthday For me?', NULL),
  (110565, 12092, 'Somebody''s head is going to roll for this!', NULL),
  (110566, 12092, 'Rule 42, you know And as for you, Your Majesty...', NULL),
  (110567, 12092, 'Well, she simply said that you''re a fat, pompous, bad-tempered, old tyrant Off with her head!', NULL),
  (110568, 12092, 'Mr Caterpillar, what will I do?', NULL),
  (110569, 12092, 'Alice Will you kindly pay attention and recite your lesson?', NULL),
  (110570, 12092, 'Alice, what are you talking about?', NULL),
  (126825, 37257, 'I''ve been hoping for a bit of sun for our homecoming.', NULL),
  (126826, 37257, 'I''m just happy that you''re your old self again.', NULL),
  (126827, 37257, 'If anything happened to you, what would happen to me, after 37 years?', NULL),
  (126828, 37257, 'They''ve deprived me of alcohol, tobacco, female companionship.', NULL),
  (126829, 37257, 'You wouldn''t, it might break your cigars.', NULL),
  (126830, 37257, 'Carter, I warn you, if this contraption should collapse, if the barrister should fall off the bannister...', NULL),
  (126831, 37257, 'Distressing news about your health.', NULL),
  (126832, 37257, 'Surely I can give him a word of advice.', NULL),
  (126833, 37257, 'You''ve probably seen reports in the press.', NULL),
  (126834, 37257, 'Can you imagine Miss Plimsoll''s face if she saw me now?', NULL),
  (126835, 37257, 'Naturally, I went to the police station.', NULL),
  (126836, 37257, 'Mr Vole, you must not take such a morbid point of view.', NULL),
  (126837, 37257, 'All right, sir, if you say so.', NULL),
  (126838, 37257, 'I haven''t had a job in four months.', NULL),
  (126839, 37257, 'She''s a wonderful wife to me, too.', NULL),
  (126840, 37257, 'Exactly how did you meet Mrs French?', NULL),
  (126841, 37257, 'I''m constantly surprised that women''s hats do not provoke more murders.', NULL),
  (126842, 37257, 'Sometimes I see the same one two or three times.', NULL),
  (126843, 37257, 'It must be cen-trifugal or centrifugal, which is it?', NULL),
  (126844, 37257, 'That''s the mask of the witch doctor.', NULL),
  (126845, 37257, 'You know, maybe I''ll take a glass of sherry myself.', NULL),
  (126846, 37257, 'She fixed a sandwich, we talked, listened to The Mikado.', NULL),
  (126847, 37257, 'I was afraid she''d lose interest.', NULL),
  (126848, 37257, 'Perhaps you turned up the volume to drown her cries.', NULL),
  (126849, 37257, 'You realise, Mr Vole, the testimony of a devoted wife does not carry much weight.', NULL),
  (126850, 37257, 'If Mr Vole had been sponging off Mrs French, why cut off the source of supply?', NULL),
  (126851, 37257, 'So now they''ll say I did have a motive.', NULL),
  (126852, 37257, 'You''re getting the de luxe treatment.', NULL),
  (126853, 37257, 'I''ve never been arrested before, not even for walking a dog off a lead or having a beer after hours.', NULL),
  (126854, 37257, 'All you''ll have is one little popgun, an alibi furnished by his wife.', NULL),
  (126855, 37257, 'Miss Plimsoll, how alluring you look, waiting like a hangman on the scaffold.', NULL),
  (126856, 37257, 'I''m glad you''re showing such fortitude.', NULL),
  (126857, 37257, 'I should have taken you to a rest-home or a resort.', NULL),
  (126858, 37257, 'How else can we take care of our own surplus.', NULL),
  (126859, 37257, 'Clearly, she had come to look upon your husband as a son or favourite nephew.', NULL),
  (126860, 37257, 'Of course I want to help Leonard.', NULL),
  (126861, 37257, 'Mrs Vole, do you love your husband?', NULL),
  (126862, 37257, 'Your husband loves you very much, does he not?', NULL),
  (126863, 37257, 'The prosecution will break her down in no time when she''s in the witness box.', NULL),
  (126864, 37257, 'They exile me to Bermuda as soon as we finish.', NULL),
  (126865, 37257, 'I want to read a portion of the evidence of Janet McKenzie, the housekeeper.', NULL),
  (126866, 37257, 'Are you keeping something from me?', NULL),
  (126867, 37257, 'All right, Frulein, if you won''t show ''em, I will.', NULL),
  (126868, 37257, 'Didn''t work too well tonight, did it?', NULL),
  (126869, 37257, 'I had a weekend pass, a month''s pay in my pocket.', NULL),
  (126870, 37257, 'Mr Vole, you must learn to trust me.', NULL),
  (126871, 37257, 'You may proceed for the prosecution, Mr Myers.', NULL),
  (126872, 37257, 'I now call Chief Inspector Hearne, Criminal Investigation Department, New Scotland Yard.', NULL),
  (126873, 37257, 'My learned patient is not above substituting brandy for cocoa.', NULL),
  (126874, 37257, 'My learned friend refers to the assailant as "the murderer".', NULL),
  (126875, 37257, 'After establishing the cause and the time of death, what did you then do?', NULL),
  (126876, 37257, 'Where did you find this, Inspector?', NULL),
  (126877, 37257, 'I submit, my lord, that it is entirely impossible to guess what went on in the mind of some entirely imaginary burglar.', NULL),
  (126878, 37257, 'Now, if such a knife were to slip, might it not inflict a cut that would bleed profusely?', NULL),
  (126879, 37257, 'I''ve no opinion of companions, poor feckless bodies, afraid of a bit of honest domestic work.', NULL),
  (126880, 37257, 'I left the house at half past seven.', NULL),
  (126881, 37257, 'But it was no business of mine, so I went upstairs to fetch my pattern.', NULL),
  (126882, 37257, 'Miss McKenzie, were you aware that Leonard Vole was a married man?', NULL),
  (126883, 37257, 'Whereas in the new will, except for a bequest to you of a small annuity, the principal beneficiary is the prisoner, Leonard Vole.', NULL),
  (126884, 37257, 'What makes you say the man''s voice was Leonard Vole''s?', NULL),
  (126885, 37257, 'Wasn''t it possible when you returned home and passed the door, what you really heard was the television and a man and woman''s voices and laughter?', NULL),
  (126886, 37257, 'I will repeat the question, my lord.', NULL),
  (126887, 37257, 'I now call the final witness for the prosecution, Christine Helm.', NULL),
  (126888, 37257, 'Mrs Helm, is this a certificate of marriage between yourself and Otto Ludwig Helm, the ceremony having taken place in Breslau on 18 April 1942?', NULL),
  (126889, 37257, 'Leonard Vole returned, you say, at ten minutes past ten.', NULL),
  (126890, 37257, 'But you''ve changed your story now.', NULL),
  (126891, 37257, 'That woman, she was a harmless old fool, and he makes of me an accomplice to the murder.', NULL),
  (126892, 37257, 'And in arranging the marriage, you lied to the authorities?', NULL),
  (126893, 37257, 'Or are you not, in fact, a chronic and habitual liar?!', NULL),
  (126894, 37257, 'Are you ready for the defence?', NULL),
  (126895, 37257, 'I objected to her testimony because a wife cannot give evidence harmful to her husband.', NULL),
  (126896, 37257, 'I am confident that no matter how searching this may be, the prisoner will withstand it.', NULL),
  (126897, 37257, 'A clinging brunette, Mr Myers?', NULL),
  (126898, 37257, 'I don''t even remember her name.', NULL),
  (126899, 37257, 'It''s just a coincidence that Mrs French should be killed only one week later?', NULL),
  (126900, 37257, 'You cut your wrist deliberately!', NULL),
  (126901, 37257, 'You need a lukewarm bath and your calcium injection.', NULL),
  (126902, 37257, 'You must think of your condition.', NULL),
  (126903, 37257, 'Let me talk to the old geezer.', NULL),
  (126904, 37257, 'I''ll be here for 30 minutes because that''s when me train leaves.', NULL),
  (126905, 37257, 'Your bath, your massage, your dinner, your injection!', NULL),
  (126906, 37257, 'Letters written to the prisoner?', NULL),
  (126907, 37257, 'That''s if you''re satisfied with ''em.', NULL),
  (126908, 37257, 'Christine Vole did that to you?', NULL),
  (126909, 37257, 'I knew I was being soft with yer.', NULL),
  (126910, 37257, 'I most strenuously object to the case being reopened at this final stage.', NULL),
  (126911, 37257, 'If you still have doubts about Mr Vole, I wouldn''t mind betting you a box of cigars.', NULL),
  (126912, 37257, 'How dare you say a thing like that?', NULL),
  (126913, 37257, 'Now, Mrs Helm, you''ve been kind enough to identify your letter paper.', NULL),
  (126914, 37257, 'But now, if this succeeds, he will be leaving me because they will take him away forever and I shall be free and yours, my beloved.', NULL),
  (126915, 37257, 'Stop pressing your luck, you''re overdue.', NULL),
  (126916, 37257, 'Do you find the prisoner at the bar, Leonard Stephen Vole, guilty or not guilty of the murder of Emily Jane French?', NULL),
  (126917, 37257, 'Let''s go before they change their mind!', NULL),
  (126918, 37257, 'But I have a ladder in my last pair of nylons.', NULL),
  (126919, 37257, 'When you said that no jury would believe an alibi given by a loving wife, no matter how much she swore he was innocent?', NULL),
  (126920, 37257, 'There''s never been anyone but Leonard.', NULL),
  (126921, 37257, 'It was you, Vole, who fooled me.', NULL),
  (126922, 37257, 'And we''ll get you a new one of these.', NULL),
  (126923, 37257, 'I''m not this girl, I''m his girl.', NULL),
  (126924, 37257, 'They''ll have you up for perjury.', NULL);
